///
/// When ON, preference/recommendation-seeking queries (per
/// [`crate::router::classify::is_preference_query`]) bypass the cross-encoder
/// reranker and keep the base RRF ranking. Built against an older "CE hurts
/// single-session-preference −0.155" measurement that did NOT reproduce on
/// either current seeded substrate (paired n=479: CE helps SSP +0.027 twice;
/// bypass −0.0117 agg, BH-sig negative). Default-OFF escape hatch only — see
/// `is_preference_query` docs for the full measurement story.
pub fn rerank_skip_preference_enabled() -> bool {
    std::env::var("WENLAN_RERANK_SKIP_PREFERENCE")
        .ok()
        .map(|v| matches!(v.trim().to_ascii_lowercase().as_str(), "1" | "true" | "yes"))
        .unwrap_or(false)
}

/// True iff `WENLAN_GRAPH_SURFACE_NEW` is truthy. OPT-IN, default OFF. Only
/// meaningful when [`graph_memory_stream_enabled`] is ON.
///
/// OFF = boost-only: the graph RRF term lifts only memories already in the base
/// pool; it can never introduce a memory the base search did not return.
///
/// ON = surface-new: graph-only linked memories (absent from the base pool) are
/// added under the bounded [`graph_surface_budget`], drawn from the same
/// type+degree-filtered anchors. The higher-recall, higher-noise arm.
pub fn graph_surface_new_enabled() -> bool {
    std::env::var("WENLAN_GRAPH_SURFACE_NEW")
        .ok()
        .map(|v| matches!(v.trim().to_ascii_lowercase().as_str(), "1" | "true" | "yes"))
        .unwrap_or(false)
}

/// Max `memory_entities` degree for an entity to qualify as a graph anchor
/// (`WENLAN_GRAPH_HUB_CAP`, default 20). Over-cap entities (speaker pools,
/// generic hubs) are EXCLUDED outright — degree is a hard filter, not a
/// tie-break. A non-positive / unparseable value falls back to the default so
/// the filter can never be silently disabled.
pub fn graph_hub_cap() -> usize {
    std::env::var("WENLAN_GRAPH_HUB_CAP")
        .ok()
        .and_then(|v| v.trim().parse::<usize>().ok())
        .filter(|n| *n > 0)
        .unwrap_or(20)
}

/// Max graph-only memories the surface-new arm may introduce per query
/// (`WENLAN_GRAPH_SURFACE_BUDGET`, default 5). Bounds the noise the higher-recall
/// arm can inject. Ignored in boost-only mode.
pub fn graph_surface_budget() -> usize {
    std::env::var("WENLAN_GRAPH_SURFACE_BUDGET")
        .ok()
        .and_then(|v| v.trim().parse::<usize>().ok())
        .unwrap_or(5)
}

/// True for entity types that name a person / conversational speaker rather than
/// a concept/topic/event. Such entities form the "speaker hairball" (one speaker
/// linked to hundreds of memories) and are excluded as graph anchors so the
/// stream surfaces concept-bridged memories, not co-speaker noise.
pub fn is_person_like(entity_type: &str) -> bool {
    matches!(
        entity_type.trim().to_ascii_lowercase().as_str(),
        "person" | "speaker" | "people" | "user"
    )
}

/// True iff `WENLAN_MAGNITUDE_FUSION` is set to a truthy value
/// (`1`, `true`, or `yes`, case-insensitive). OPT-IN: when unset or falsey,
/// `search_memory`'s FTS channel keeps the legacy rank-only RRF term
/// `fts_weight/(rrf_k+rank)` (byte-identical default behavior).
///
/// When enabled, the FTS channel preserves BM25 magnitude: the raw-negative
/// FTS5 bm25 captured into `SearchResult::score` is negated, min-max normalized
/// across the FTS result set, and contributed as `fts_weight * norm / rrf_k`. The
/// constant-`rrf_k` divisor scale-matches the vector channel (max `1.0/rrf_k`) so
/// the FTS channel keeps the same relative weight the rank-only term gave it (max
/// `fts_weight/rrf_k`) instead of overwhelming vector, while the normalized
/// magnitude differentiates strong vs weak matches. This fixes the discard
/// asymmetry where the vector channel already weights by cosine magnitude but the
/// FTS channel threw its bm25 magnitude away.
///
/// Used by `search_memory` to gate the fusion branch and by the eval harness
/// (locomo + longmemeval) to tag baseline JSON artifacts with their
/// magfusion-ON/OFF variant. Both sites MUST share this helper so an
/// `WENLAN_MAGNITUDE_FUSION` setting can't disagree between production and eval
/// (which would make baseline filenames lie — see AGENTS.md Eval Citation
/// Discipline).
///
/// Note: min-max is PER-QUERY, so absolute fused scores are not comparable
/// across queries (fine for single-query ranking; a future cross-query
/// score_threshold would need a different normalization).
pub fn magnitude_fusion_enabled() -> bool {
    std::env::var("WENLAN_MAGNITUDE_FUSION")
        .ok()
        .map(|v| matches!(v.trim().to_ascii_lowercase().as_str(), "1" | "true" | "yes"))
        .unwrap_or(false)
}

/// Sign-correct a raw FTS5 bm25 score into a non-negative magnitude.
///
/// THE #1 FOOTGUN: production `search_memory` captures the RAW NEGATIVE FTS5
/// bm25 into `SearchResult::score` (`rank as f32`, NOT negated — unlike
/// `fts_only_search`, which negates at capture). FTS5 bm25 is negative and a
/// STRONGER match is MORE negative, so we must negate FIRST: a stronger match
/// becomes a LARGER positive magnitude. Skipping the negate inverts the channel
/// and sinks strong matches. The `.max(0.0)` guards the rare non-negative bm25.
///
/// Unit-tested directly (`fts_magnitude_sign_is_monotonic`) so the sign is
/// pinned independent of the vector channel, which co-varies with FTS in
/// integration and can mask an inversion.
#[inline]
fn fts_magnitude(raw_bm25: f32) -> f32 {
    (-raw_bm25).max(0.0)
}

/// Min-max normalize a slice of (already sign-corrected, non-negative) FTS
/// magnitudes into `[0.0, 1.0]`. Used by the `WENLAN_MAGNITUDE_FUSION` path in
/// `search_memory`.
///
/// Guards: empty → empty; a single element or an all-equal set (`max - min`
/// below `eps`) → all `1.0` (mirrors the POC guard
/// `if fts_max > 0.0 { fts_max } else { 1.0 }` in `vector_plus_fts_search`).
/// Never emits NaN/inf.
fn normalize_fts_magnitudes(scores: &[f32]) -> Vec<f32> {
    if scores.is_empty() {
        return Vec::new();
    }
    let min = scores.iter().copied().fold(f32::INFINITY, f32::min);
    let max = scores.iter().copied().fold(f32::NEG_INFINITY, f32::max);
    let range = max - min;
    const EPS: f32 = 1e-6;
    if range > EPS {
        scores.iter().map(|&s| (s - min) / range).collect()
    } else {
        // Single element or all-equal: no spread to normalize → treat as full.
        vec![1.0; scores.len()]
    }
}

/// Bigram Jaccard similarity between two strings (0.0–1.0).
/// Used for content-based deduplication in search results.
fn bigram_jaccard(a: &str, b: &str) -> f64 {
    fn bigrams(s: &str) -> HashSet<(char, char)> {
        let lower: Vec<char> = s.chars().flat_map(|c| c.to_lowercase()).collect();
        lower.windows(2).map(|w| (w[0], w[1])).collect()
    }
    let ba = bigrams(a);
    let bb = bigrams(b);
    let union = ba.union(&bb).count();
    if union == 0 {
        return 1.0;
    }
    ba.intersection(&bb).count() as f64 / union as f64
}

/// Row data for clustering algorithm
struct ClusterMemRow {
    source_id: String,
    content: String,
    entity_id: Option<String>,
    entity_name: Option<String>,
    space: Option<String>,
    /// True when this row is an agent capture eligible to SEED a new page.
    /// Folder-ingested documents (`source_agent='folder'`/`'reconcile'` or
    /// carrying a folder content-hash) are recruited as evidence but never
    /// seed — a book must not mint pages from its own chapters (spec §4.2).
    can_seed_page: bool,
    embedding: Vec<f32>,
}

/// Cosine similarity between two embedding vectors.
pub(crate) fn cosine_similarity(a: &[f32], b: &[f32]) -> f64 {
    let mut dot = 0.0f64;
    let mut norm_a = 0.0f64;
    let mut norm_b = 0.0f64;
    for (x, y) in a.iter().zip(b.iter()) {
        let x = *x as f64;
        let y = *y as f64;
        dot += x * y;
        norm_a += x * x;
        norm_b += y * y;
    }
    let denom = norm_a.sqrt() * norm_b.sqrt();
    if denom == 0.0 {
        0.0
    } else {
        dot / denom
    }
}

/// Greedy clustering: attach each memory to the first cluster where
/// cosine similarity with the centroid exceeds threshold.
fn cluster_by_similarity(
    memories: &[ClusterMemRow],
    indices: &[usize],
    threshold: f64,
) -> Vec<Vec<usize>> {
    let mut clusters: Vec<(Vec<usize>, Vec<f32>)> = Vec::new();

    for &idx in indices {
        let emb = &memories[idx].embedding;
        let mut assigned = false;
        for (group, centroid) in clusters.iter_mut() {
            if cosine_similarity(emb, centroid) >= threshold {
                group.push(idx);
                // Update centroid as running average
                for (j, val) in emb.iter().enumerate() {
                    centroid[j] += (val - centroid[j]) / group.len() as f32;
                }
                assigned = true;
                break;
            }
        }
        if !assigned {
            clusters.push((vec![idx], emb.clone()));
        }
    }

    clusters.into_iter().map(|(g, _)| g).collect()
}

fn build_distillation_cluster(
    memories: &[ClusterMemRow],
    indices: &[usize],
) -> DistillationCluster {
    let source_ids: Vec<String> = indices
        .iter()
        .map(|&i| memories[i].source_id.clone())
        .collect();
    let contents: Vec<String> = indices
        .iter()
        .map(|&i| memories[i].content.clone())
        .collect();
    let entity_id = memories[indices[0]].entity_id.clone();
    let entity_name = memories[indices[0]].entity_name.clone();
    let space = memories[indices[0]].space.clone();
    let estimated_tokens = contents.iter().map(|c| c.len() / 4 + 15).sum::<usize>() + 100;
    // Mean-pool member embeddings into a cluster centroid so the scoped
    // dedup matcher (find_matching_page_scoped) has a vector to compare.
    // Skip dims only if every member embedding is empty.
    let dim = memories[indices[0]].embedding.len();
    let centroid_embedding = if dim == 0 {
        None
    } else {
        let mut acc = vec![0.0f32; dim];
        let mut n = 0usize;
        for &i in indices {
            let e = &memories[i].embedding;
            if e.len() == dim {
                for (a, v) in acc.iter_mut().zip(e.iter()) {
                    *a += *v;
                }
                n += 1;
            }
        }
        if n == 0 {
            None
        } else {
            for a in acc.iter_mut() {
                *a /= n as f32;
            }
            Some(acc)
        }
    };
    DistillationCluster {
        source_ids,
        contents,
        entity_id,
        entity_name,
        space,
        estimated_tokens,
        centroid_embedding,
    }
}

/// Split a cluster that exceeds the LLM's token limit.
/// Uses farthest-first seed selection + nearest-centroid assignment.
/// No memory count cap — conceptual coherence is an LLM judgment, not a number.
fn sub_cluster_by_tokens(
    memories: &[ClusterMemRow],
    cluster: DistillationCluster,
    token_limit: usize,
    min_size: usize,
) -> Vec<DistillationCluster> {
    if cluster.estimated_tokens <= token_limit {
        // Floor re-check: a below-floor cluster that fit under the token
        // limit still must not slip through as a candidate (spec §4.3).
        return if cluster.source_ids.len() >= min_size {
            vec![cluster]
        } else {
            Vec::new()
        };
    }

    let k = (cluster.estimated_tokens as f64 / token_limit as f64).ceil() as usize;
    let k = k.max(2);

    // Map source_ids back to indices in the memories array
    let indices: Vec<usize> = cluster
        .source_ids
        .iter()
        .filter_map(|sid| memories.iter().position(|m| m.source_id == *sid))
        .collect();

    if indices.len() <= k {
        // Each memory would land in its own singleton sub-cluster. Emit them
        // only when the floor permits singletons (min_size <= 1); otherwise
        // drop — a token split must never manufacture below-floor clusters.
        return indices
            .iter()
            .filter(|_| min_size <= 1)
            .map(|&i| build_distillation_cluster(memories, &[i]))
            .collect();
    }

    // Farthest-first seed selection
    let mut seeds: Vec<usize> = Vec::with_capacity(k);
    seeds.push(indices[0]);

    for _ in 1..k {
        let mut best_idx = indices[0];
        let mut best_min_dist = f64::NEG_INFINITY;
        for &idx in &indices {
            if seeds.contains(&idx) {
                continue;
            }
            let min_dist = seeds
                .iter()
                .map(|&s| 1.0 - cosine_similarity(&memories[idx].embedding, &memories[s].embedding))
                .fold(f64::INFINITY, f64::min);
            if min_dist > best_min_dist {
                best_min_dist = min_dist;
                best_idx = idx;
            }
        }
        seeds.push(best_idx);
    }

    // Assign each memory to nearest seed
    let mut assignments: Vec<Vec<usize>> = vec![Vec::new(); k];
    for &idx in &indices {
        let mut best_k = 0;
        let mut best_sim = f64::NEG_INFINITY;
        for (ki, &seed) in seeds.iter().enumerate() {
            let sim = cosine_similarity(&memories[idx].embedding, &memories[seed].embedding);
            if sim > best_sim {
                best_sim = sim;
                best_k = ki;
            }
        }
        assignments[best_k].push(idx);
    }

    assignments
        .into_iter()
        .filter(|group| group.len() >= min_size)
        .map(|group| build_distillation_cluster(memories, &group))
        .collect()
}

/// Seeding floor (spec §4.2/§4.3, many-to-many): a candidate cluster may seed
/// a new page only when at least `MIN_CAPTURE_SEED_MEMBERS` of its members are
/// agent captures (`can_seed_page`). Folder documents are recruited as
/// evidence but never count toward the seed floor.
fn has_capture_seed_floor(memories: &[ClusterMemRow], cluster: &DistillationCluster) -> bool {
    const MIN_CAPTURE_SEED_MEMBERS: usize = 3;
    cluster
        .source_ids
        .iter()
        .filter(|source_id| {
            memories
                .iter()
                .any(|memory| memory.source_id == **source_id && memory.can_seed_page)
        })
        .count()
        >= MIN_CAPTURE_SEED_MEMBERS
}

#[derive(Debug, Clone, Copy)]
enum DistillationClusterMode {
    SpaceScoped,
    Global,
}

#[allow(clippy::too_many_arguments)]
fn cluster_distillation_rows(
    memories: &[ClusterMemRow],
    similarity_threshold: f64,
    min_size: usize,
    max_clusters: usize,
    token_limit: usize,
    max_unlinked_cluster_size: usize,
    max_grouped_cluster_size: usize,
    mode: DistillationClusterMode,
) -> Vec<DistillationCluster> {
    let mut clusters: Vec<DistillationCluster> = Vec::new();

    let emit_split = |cluster: DistillationCluster, clusters: &mut Vec<DistillationCluster>| {
        for split in sub_cluster_by_tokens(memories, cluster, token_limit, min_size) {
            if has_capture_seed_floor(memories, &split) {
                clusters.push(split);
            }
        }
    };

    let process_bucket = |bucket_label: &str,
                          indices: &[usize],
                          cap: usize,
                          clusters: &mut Vec<DistillationCluster>| {
        let sub = cluster_by_similarity(memories, indices, similarity_threshold);
        for group in sub {
            if group.len() < min_size {
                continue;
            }
            if group.len() > cap {
                let tighter = (similarity_threshold + 0.05).min(0.92);
                log::info!(
                    "[distill] re-splitting oversized {} cluster: \
                         {} memories at threshold {:.2} (cap = {})",
                    bucket_label,
                    group.len(),
                    tighter,
                    cap,
                );
                let resplit = cluster_by_similarity(memories, &group, tighter);
                for sub_group in resplit {
                    if sub_group.len() < min_size {
                        continue;
                    }
                    if sub_group.len() > cap {
                        log::warn!(
                            "[distill] dropping {} sub-cluster after re-split: \
                                 {} memories still > cap {} -- raise \
                                 max_{}_cluster_size if this is a genuine page",
                            bucket_label,
                            sub_group.len(),
                            cap,
                            bucket_label,
                        );
                        continue;
                    }
                    let cluster = build_distillation_cluster(memories, &sub_group);
                    emit_split(cluster, clusters);
                }
                continue;
            }
            let cluster = build_distillation_cluster(memories, &group);
            emit_split(cluster, clusters);
        }
    };

    match mode {
        DistillationClusterMode::SpaceScoped => {
            let mut space_groups: std::collections::HashMap<String, Vec<usize>> =
                std::collections::HashMap::new();
            let mut unlinked: Vec<usize> = Vec::new();

            for (i, mem) in memories.iter().enumerate() {
                match mem.space.as_deref() {
                    Some(space) if !space.is_empty() => {
                        space_groups.entry(space.to_string()).or_default().push(i);
                    }
                    _ => unlinked.push(i),
                }
            }

            for indices in space_groups.values() {
                process_bucket("space", indices, max_grouped_cluster_size, &mut clusters);
            }

            if unlinked.len() >= min_size {
                process_bucket(
                    "unlinked",
                    &unlinked,
                    max_unlinked_cluster_size,
                    &mut clusters,
                );
            }

            log::info!(
                "[distill] space_groups={}, unlinked={}, clusters_found={}",
                space_groups.len(),
                unlinked.len(),
                clusters.len()
            );
        }
        DistillationClusterMode::Global => {
            let indices: Vec<usize> = (0..memories.len()).collect();
            if indices.len() >= min_size {
                process_bucket("global", &indices, max_grouped_cluster_size, &mut clusters);
            }
            log::info!(
                "[distill] global_candidates={}, clusters_found={}",
                indices.len(),
                clusters.len()
            );
        }
    }

    clusters.sort_by_key(|c| std::cmp::Reverse(c.source_ids.len()));
    clusters.truncate(max_clusters);
    clusters
}

