    /// Update a single memory's content (and re-embed).
    pub async fn update_memory(&self, id: &str, new_content: &str) -> Result<(), WenlanError> {
        self.apply_memory_update(id, Some(new_content), None, false, None)
            .await
    }

    pub(crate) async fn apply_memory_update(
        &self,
        source_id: &str,
        new_content: Option<&str>,
        requested_space: Option<Option<&str>>,
        confirm: bool,
        requested_memory_type: Option<&str>,
    ) -> Result<(), WenlanError> {
        if new_content.is_none()
            && requested_space.is_none()
            && !confirm
            && requested_memory_type.is_none()
        {
            return Ok(());
        }

        struct HeadMetadata {
            source: String,
            title: String,
            structured_fields: Option<String>,
            source_text: Option<String>,
            memory_type: Option<String>,
            space: Option<String>,
            source_agent: Option<String>,
            confidence: Option<f64>,
            confirmed: Option<i64>,
            stability: String,
            pending_revision: i64,
            last_modified: i64,
            supersede_mode: String,
            created_at: i64,
        }

        let head = {
            let conn = self.conn.lock().await;
            let mut rows = conn
                .query(
                    "SELECT source, title, structured_fields, source_text, memory_type,
                            space, source_agent, confidence, confirmed, stability,
                            pending_revision, last_modified, supersede_mode,
                            COALESCE(created_at, last_modified)
                     FROM memories
                     WHERE source_id = ?1 AND source != 'episode' AND chunk_index = 0
                     LIMIT 1",
                    libsql::params![source_id],
                )
                .await
                .map_err(|e| WenlanError::VectorDb(format!("update_memory read: {e}")))?;
            let Some(row) = rows
                .next()
                .await
                .map_err(|e| WenlanError::VectorDb(format!("update_memory row: {e}")))?
            else {
                return Ok(());
            };
            HeadMetadata {
                source: row.get(0).unwrap_or_else(|_| "memory".to_string()),
                title: row.get(1).unwrap_or_default(),
                structured_fields: row.get::<Option<String>>(2).unwrap_or(None),
                source_text: row.get::<Option<String>>(3).unwrap_or(None),
                memory_type: row.get::<Option<String>>(4).unwrap_or(None),
                space: row.get::<Option<String>>(5).unwrap_or(None),
                source_agent: row.get::<Option<String>>(6).unwrap_or(None),
                confidence: row.get::<Option<f64>>(7).unwrap_or(None),
                confirmed: row.get::<Option<i64>>(8).unwrap_or(None),
                stability: row
                    .get::<Option<String>>(9)
                    .unwrap_or(None)
                    .unwrap_or_else(|| "new".to_string()),
                pending_revision: row.get::<Option<i64>>(10).unwrap_or(None).unwrap_or(0),
                last_modified: row.get(11).unwrap_or(0),
                supersede_mode: row
                    .get::<Option<String>>(12)
                    .unwrap_or(None)
                    .unwrap_or_else(|| "hide".to_string()),
                created_at: row.get(13).unwrap_or(0),
            }
        };

        let content_embedding = new_content
            .map(|content| {
                self.get_or_compute_embedding(content)
                    .map(|v| Self::vec_to_sql(&v))
            })
            .transpose()?;

        struct PreparedChild {
            id: String,
            field: String,
            content: String,
            embedding: String,
        }

        let fact_enabled = crate::retrieval::fact_channel::fact_channel_enabled();
        let prepared_children = if head.source == "memory" && new_content.is_some() && fact_enabled
        {
            let fields = derive_memory_child_fields(
                new_content.unwrap_or_default(),
                head.structured_fields.as_deref(),
            );
            let texts: Vec<String> = fields.iter().map(|(_, text)| text.clone()).collect();
            let embeddings = if texts.is_empty() {
                Vec::new()
            } else {
                self.generate_embeddings(&texts)?
            };
            if embeddings.len() != fields.len() {
                return Err(WenlanError::Embedding(format!(
                    "Expected {} child embeddings, got {}",
                    fields.len(),
                    embeddings.len()
                )));
            }
            fields
                .into_iter()
                .zip(embeddings.iter())
                .map(|((field, content), embedding)| PreparedChild {
                    id: child_vector_id(source_id, &field),
                    field,
                    content,
                    embedding: Self::vec_to_sql(embedding),
                })
                .collect()
        } else {
            Vec::new()
        };

        enum EpisodeMutation {
            Preserve,
            Delete,
            Replace {
                derivation: EpisodeDerivation,
                embedding: String,
            },
        }

        let episode_mutation = if head.source != "memory"
            || new_content.is_none()
            || head.source_text.is_some()
        {
            EpisodeMutation::Preserve
        } else if episode_channel_enabled() {
            match derive_episode(
                source_id,
                None,
                new_content.unwrap_or_default(),
                episode_word_gate(),
            ) {
                Some(derivation) => {
                    let embeddings =
                        self.generate_embeddings(std::slice::from_ref(&derivation.verbatim))?;
                    let embedding = embeddings.first().ok_or_else(|| {
                        WenlanError::Embedding("Expected one episode embedding, got zero".into())
                    })?;
                    EpisodeMutation::Replace {
                        derivation,
                        embedding: Self::vec_to_sql(embedding),
                    }
                }
                None => EpisodeMutation::Delete,
            }
        } else {
            EpisodeMutation::Delete
        };

        let requested_space =
            requested_space.map(|space| space.map(std::string::ToString::to_string));
        let requested_memory_type = requested_memory_type.map(str::to_string);
        let effective_space = requested_space
            .clone()
            .unwrap_or_else(|| head.space.clone());
        let effective_memory_type = requested_memory_type
            .clone()
            .or_else(|| head.memory_type.clone());
        let effective_confidence = if confirm { Some(1.0) } else { head.confidence };
        let effective_confirmed = if confirm { Some(1) } else { head.confirmed };
        let effective_stability = if confirm {
            "confirmed".to_string()
        } else {
            head.stability.clone()
        };

        let _fact_activity = (head.source == "memory" && new_content.is_some()).then(|| {
            self.begin_derived_artifact_write(crate::derived_artifact_state::DerivedArtifact::Fact)
        });
        let _episode_activity = (head.source == "memory" && new_content.is_some()).then(|| {
            self.begin_derived_artifact_write(
                crate::derived_artifact_state::DerivedArtifact::Episode,
            )
        });

        let conn = self.conn.lock().await;
        conn.execute("BEGIN", ())
            .await
            .map_err(|e| WenlanError::VectorDb(format!("update_memory begin: {e}")))?;

        let mutation_result: Result<(), WenlanError> = async {
            if let (Some(content), Some(embedding)) = (new_content, content_embedding.as_deref()) {
                let affected = conn
                    .execute(
                        "UPDATE memories
                         SET content = ?1, embedding = vector32(?2), word_count = ?3
                         WHERE source_id = ?4 AND chunk_index = 0 AND source != 'episode'",
                        libsql::params![
                            content,
                            embedding,
                            content.split_whitespace().count() as i64,
                            source_id
                        ],
                    )
                    .await
                    .map_err(|e| WenlanError::VectorDb(format!("update_memory head: {e}")))?;
                if affected == 0 {
                    return Err(WenlanError::Conflict(format!(
                        "memory {source_id} changed before update"
                    )));
                }

                conn.execute(
                    "DELETE FROM memories
                     WHERE source_id = ?1 AND source != 'episode' AND chunk_index > 0",
                    libsql::params![source_id],
                )
                .await
                .map_err(|e| WenlanError::VectorDb(format!("update_memory stale chunks: {e}")))?;

                if head.source == "memory" {
                    conn.execute(
                        "DELETE FROM child_vectors
                         WHERE parent_kind = 'memory' AND parent_id = ?1",
                        libsql::params![source_id],
                    )
                    .await
                    .map_err(|e| {
                        WenlanError::VectorDb(format!("update_memory child delete: {e}"))
                    })?;
                    for child in prepared_children {
                        conn.execute(
                            "INSERT OR REPLACE INTO child_vectors
                             (id, parent_kind, parent_id, field, content, embedding)
                             VALUES (?1, 'memory', ?2, ?3, ?4, vector32(?5))",
                            libsql::params![
                                child.id,
                                source_id,
                                child.field,
                                child.content,
                                child.embedding
                            ],
                        )
                        .await
                        .map_err(|e| {
                            WenlanError::VectorDb(format!("update_memory child insert: {e}"))
                        })?;
                    }

                    match episode_mutation {
                        EpisodeMutation::Preserve => {}
                        EpisodeMutation::Delete => {
                            conn.execute(
                                "DELETE FROM memories
                                 WHERE source = 'episode' AND source_id = ?1",
                                libsql::params![source_id],
                            )
                            .await
                            .map_err(|e| {
                                WenlanError::VectorDb(format!("update_memory episode delete: {e}"))
                            })?;
                        }
                        EpisodeMutation::Replace {
                            derivation,
                            embedding,
                        } => {
                            conn.execute(
                                "DELETE FROM memories
                                 WHERE source = 'episode' AND source_id = ?1",
                                libsql::params![source_id],
                            )
                            .await
                            .map_err(|e| {
                                WenlanError::VectorDb(format!("update_memory episode delete: {e}"))
                            })?;
                            conn.execute(
                                "INSERT INTO memories (id, content, source, source_id, title,
                                    summary, url, chunk_index, last_modified, chunk_type,
                                    language, byte_start, byte_end, semantic_unit, memory_type,
                                    space, source_agent, confidence, confirmed, stability,
                                    supersedes, pending_revision, word_count, entity_id,
                                    enrichment_status, quality, is_recap, supersede_mode,
                                    structured_fields, retrieval_cue, source_text, embedding,
                                    created_at, importance, episode_of)
                                 VALUES (?1, ?2, 'episode', ?3, ?4,
                                    NULL, NULL, 0, ?5, 'text',
                                    NULL, NULL, NULL, NULL, ?6,
                                    ?7, ?8, ?9, ?10, ?11,
                                    NULL, ?12, ?13, NULL,
                                    'legacy', NULL, 0, ?14,
                                    NULL, NULL, NULL, vector32(?15),
                                    ?16, NULL, ?17)",
                                libsql::params![
                                    derivation.episode_id,
                                    derivation.verbatim,
                                    source_id,
                                    head.title,
                                    head.last_modified,
                                    effective_memory_type,
                                    effective_space,
                                    head.source_agent,
                                    effective_confidence,
                                    effective_confirmed,
                                    effective_stability,
                                    head.pending_revision,
                                    derivation.word_count,
                                    head.supersede_mode,
                                    embedding,
                                    head.created_at,
                                    source_id
                                ],
                            )
                            .await
                            .map_err(|e| {
                                WenlanError::VectorDb(format!("update_memory episode insert: {e}"))
                            })?;
                        }
                    }
                }
            }

            if let Some(space) = requested_space {
                conn.execute(
                    "UPDATE memories SET space = ?1 WHERE source_id = ?2",
                    libsql::params![space, source_id],
                )
                .await
                .map_err(|e| WenlanError::VectorDb(format!("update_memory space: {e}")))?;
            }
            if let Some(memory_type) = requested_memory_type {
                conn.execute(
                    "UPDATE memories SET memory_type = ?1 WHERE source_id = ?2",
                    libsql::params![memory_type, source_id],
                )
                .await
                .map_err(|e| WenlanError::VectorDb(format!("update_memory type: {e}")))?;
            }
            if confirm {
                conn.execute(
                    "UPDATE memories
                     SET stability = 'confirmed', confirmed = 1, confidence = 1.0
                     WHERE source_id = ?1 AND source = 'memory'",
                    libsql::params![source_id],
                )
                .await
                .map_err(|e| WenlanError::VectorDb(format!("update_memory confirm: {e}")))?;
            }
            Ok(())
        }
        .await;

        if let Err(error) = mutation_result {
            if let Err(rollback_error) = conn.execute("ROLLBACK", ()).await {
                return Err(WenlanError::VectorDb(format!(
                    "{error}; rollback failed: {rollback_error}"
                )));
            }
            return Err(error);
        }
        if let Err(error) = conn.execute("COMMIT", ()).await {
            if let Err(rollback_error) = conn.execute("ROLLBACK", ()).await {
                return Err(WenlanError::VectorDb(format!(
                    "update_memory commit: {error}; rollback failed: {rollback_error}"
                )));
            }
            return Err(WenlanError::VectorDb(format!(
                "update_memory commit: {error}"
            )));
        }
        Ok(())
    }

    /// Rebuild the `child_vectors` rows for a single parent memory from its
    /// CURRENT content + structured_fields (T15a). Delete-then-insert by
    /// `parent_id` in one tx so no stale child survives an in-place content
    /// edit. No-op (and no child rows) when `fact_channel_enabled()` is false.
    ///
    /// Idempotent: child ids are `sha256(parent_id + field)[..16]`, so a rebuild
    /// over unchanged content produces the same rows. Called from the in-place
    /// content-change paths (`update_memory`, `upsert_memory_in_place`) so a
    /// surgical edit outside the `upsert_documents` store path keeps children in
    /// sync.
    pub async fn rebuild_child_vectors_for(&self, parent_id: &str) -> Result<(), WenlanError> {
        if !crate::retrieval::fact_channel::fact_channel_enabled() {
            return Ok(());
        }

        // Read the current primary-chunk content + structured_fields.
        let (content, structured_fields): (String, Option<String>) = {
            let conn = self.conn.lock().await;
            let mut rows = conn
                .query(
                    "SELECT content, structured_fields FROM memories
                     WHERE source_id = ?1 AND source = 'memory' AND chunk_index = 0
                     LIMIT 1",
                    libsql::params![parent_id.to_string()],
                )
                .await
                .map_err(|e| WenlanError::VectorDb(format!("rebuild_child read: {e}")))?;
            match rows.next().await {
                Ok(Some(row)) => (
                    row.get::<String>(0).unwrap_or_default(),
                    row.get::<Option<String>>(1).unwrap_or(None),
                ),
                _ => return Ok(()), // parent gone; nothing to rebuild
            }
        };

        // Build (field, text) children: narrative + per structured field.
        let fields = derive_memory_child_fields(&content, structured_fields.as_deref());

        let texts: Vec<String> = fields.iter().map(|(_, t)| t.clone()).collect();
        let embeddings = if texts.is_empty() {
            Vec::new()
        } else {
            self.generate_embeddings(&texts)?
        };

        let conn = self.conn.lock().await;
        conn.execute("BEGIN", ())
            .await
            .map_err(|e| WenlanError::VectorDb(format!("rebuild_child begin: {e}")))?;
        conn.execute(
            "DELETE FROM child_vectors WHERE parent_kind = 'memory' AND parent_id = ?1",
            libsql::params![parent_id.to_string()],
        )
        .await
        .map_err(|e| WenlanError::VectorDb(format!("rebuild_child delete: {e}")))?;
        for ((field, text), embedding) in fields.into_iter().zip(embeddings.iter()) {
            let child_id = child_vector_id(parent_id, &field);
            let vec_str = Self::vec_to_sql(embedding);
            conn.execute(
                "INSERT OR REPLACE INTO child_vectors (id, parent_kind, parent_id, field, content, embedding)
                 VALUES (?1, 'memory', ?2, ?3, ?4, vector32(?5))",
                libsql::params![child_id, parent_id.to_string(), field, text, vec_str],
            )
            .await
            .map_err(|e| WenlanError::VectorDb(format!("rebuild_child insert: {e}")))?;
        }
        conn.execute("COMMIT", ())
            .await
            .map_err(|e| WenlanError::VectorDb(format!("rebuild_child commit: {e}")))?;
        Ok(())
    }

    /// Idempotent backfill: rebuild `child_vectors` for every `source='memory'`
    /// parent that currently has NO child rows (T15a). This is the supported
    /// turn-it-on-later path — after migration 58 or after flipping
    /// `WENLAN_ENABLE_FACT_CHANNEL` on, the table is empty, so a DB ingested with
    /// the flag off needs this pass before the read channel can surface anything.
    ///
    /// No-op when `fact_channel_enabled()` is false. Returns the number of
    /// parents rebuilt.
    pub async fn rebuild_child_vectors_for_missing(&self) -> Result<usize, WenlanError> {
        if !crate::retrieval::fact_channel::fact_channel_enabled() {
            return Ok(0);
        }
        let _activity =
            self.begin_derived_artifact_write(crate::derived_artifact_state::DerivedArtifact::Fact);
        // Find primary-chunk memory parents with no child_vectors rows yet.
        let missing: Vec<String> = {
            let conn = self.conn.lock().await;
            let mut rows = conn
                .query(
                    "SELECT m.source_id FROM memories m
                     WHERE m.source = 'memory' AND m.chunk_index = 0
                       AND NOT EXISTS (
                           SELECT 1 FROM child_vectors cv
                           WHERE cv.parent_kind = 'memory' AND cv.parent_id = m.source_id
                       )",
                    (),
                )
                .await
                .map_err(|e| WenlanError::VectorDb(format!("rebuild_missing scan: {e}")))?;
            let mut ids = Vec::new();
            while let Ok(Some(row)) = rows.next().await {
                if let Ok(id) = row.get::<String>(0) {
                    ids.push(id);
                }
            }
            ids
        };
        let mut rebuilt = 0usize;
        for id in &missing {
            self.rebuild_child_vectors_for(id).await?;
            rebuilt += 1;
        }
        Ok(rebuilt)
    }

    /// Replace entire document content: re-chunk, re-embed, re-insert.
    pub async fn update_document_content(
        &self,
        source_id: &str,
        new_content: &str,
    ) -> Result<(), WenlanError> {
        // Get existing doc metadata from current memories
        let conn = self.conn.lock().await;
        let mut rows = conn
            .query(
                "SELECT source, title, url, summary, memory_type, space, source_agent,
                        confidence, confirmed, supersedes, last_modified
                 FROM memories WHERE source_id = ?1 LIMIT 1",
                libsql::params![source_id.to_string()],
            )
            .await
            .map_err(|e| WenlanError::VectorDb(format!("update_doc_content: {}", e)))?;

        let meta = if let Ok(Some(row)) = rows.next().await {
            Some((
                row.get::<String>(0).unwrap_or_default(),
                row.get::<String>(1).unwrap_or_default(),
                row.get::<Option<String>>(2).unwrap_or(None),
                row.get::<Option<String>>(3).unwrap_or(None),
                row.get::<Option<String>>(4).unwrap_or(None),
                row.get::<Option<String>>(5).unwrap_or(None),
                row.get::<Option<String>>(6).unwrap_or(None),
                row.get::<Option<f64>>(7).unwrap_or(None).map(|v| v as f32),
                row.get::<Option<i64>>(8).unwrap_or(None).map(|v| v != 0),
                row.get::<Option<String>>(9).unwrap_or(None),
                row.get::<i64>(10).unwrap_or(0),
            ))
        } else {
            None
        };
        drop(rows);
        drop(conn);

        if let Some((
            source,
            title,
            url,
            summary,
            memory_type,
            space,
            source_agent,
            confidence,
            confirmed,
            supersedes,
            last_modified,
        )) = meta
        {
            let doc = RawDocument {
                source,
                source_id: source_id.to_string(),
                title,
                summary,
                content: new_content.to_string(),
                url,
                last_modified,
                metadata: HashMap::new(),
                memory_type,
                space,
                source_agent,
                confidence,
                confirmed,
                supersedes,
                pending_revision: false,
                ..Default::default()
            };
            self.upsert_documents(vec![doc]).await?;
        }

        Ok(())
    }

    /// Count memories per source.
    pub async fn count_by_source(&self) -> Result<HashMap<String, u64>, WenlanError> {
        let conn = self.conn.lock().await;
        let mut rows = conn
            .query("SELECT source, COUNT(*) FROM memories GROUP BY source", ())
            .await
            .map_err(|e| WenlanError::VectorDb(format!("count_by_source: {}", e)))?;

        let mut map = HashMap::new();
        while let Ok(Some(row)) = rows.next().await {
            let source: String = row.get(0).unwrap_or_default();
            let count: i64 = row.get(1).unwrap_or(0);
            map.insert(source, count as u64);
        }
        Ok(map)
    }

    /// List memories with optional filters, returning rich MemoryItem structs for the UI.
    pub async fn list_memories(
        &self,
        space: Option<&str>,
        memory_type: Option<&str>,
        confirmed: Option<bool>,
        pinned: Option<bool>,
        limit: usize,
    ) -> Result<Vec<MemoryItem>, WenlanError> {
        let conn = self.conn.lock().await;

        let mut sql = String::from(
            "SELECT source_id, title,
                    GROUP_CONCAT(content, '\n') as content,
                    MAX(summary) as summary,
                    MAX(memory_type) as memory_type,
                    MAX(space) as space,
                    MAX(source_agent) as source_agent,
                    MAX(confidence) as confidence,
                    MAX(confirmed) as confirmed,
                    MAX(stability) as stability,
                    MAX(pinned) as pinned,
                    MAX(supersedes) as supersedes,
                    MAX(last_modified) as last_modified,
                    COUNT(*) as chunk_count,
                    MAX(entity_id) as entity_id,
                    MAX(quality) as quality,
                    MAX(is_recap) as is_recap,
                    (SELECT CASE
                        WHEN COUNT(es.source_id) = 0 THEN 'raw'
                        WHEN SUM(CASE WHEN es.status = 'failed' OR es.status = 'abandoned' THEN 1 ELSE 0 END) = 0 THEN 'enriched'
                        WHEN SUM(CASE WHEN es.status IN ('ok','skipped') THEN 1 ELSE 0 END) = 0 THEN 'enrichment_failed'
                        ELSE 'enrichment_partial'
                    END FROM enrichment_steps es WHERE es.source_id = memories.source_id) AS enrichment_status,
                    MAX(supersede_mode) as supersede_mode,
                    MAX(structured_fields) as structured_fields,
                    MAX(retrieval_cue) as retrieval_cue,
                    SUM(access_count) as access_count,
                    MAX(source_text) as source_text,
                    MAX(version) as version,
                    MAX(changelog) as changelog
             FROM memories
             WHERE source = 'memory'
               AND pending_revision = 0
               AND source_id NOT IN (SELECT supersedes FROM memories WHERE supersedes IS NOT NULL AND pending_revision = 0 AND source = 'memory' GROUP BY supersedes)"
        );
        let mut params: Vec<libsql::Value> = Vec::new();

        if let Some(d) = space {
            if d == "uncategorized" {
                sql.push_str(" AND space IS NULL");
            } else {
                params.push(d.into());
                sql.push_str(&format!(" AND space = ?{}", params.len()));
            }
        }
        if let Some(mt) = memory_type {
            params.push(mt.into());
            sql.push_str(&format!(" AND memory_type = ?{}", params.len()));
        }
        if let Some(c) = confirmed {
            params.push(if c { 1i64.into() } else { 0i64.into() });
            sql.push_str(&format!(" AND confirmed = ?{}", params.len()));
        }
        if let Some(p) = pinned {
            params.push(if p { 1i64.into() } else { 0i64.into() });
            sql.push_str(&format!(" AND pinned = ?{}", params.len()));
        }

        sql.push_str(" GROUP BY source_id ORDER BY last_modified DESC");
        params.push((limit as i64).into());
        sql.push_str(&format!(" LIMIT ?{}", params.len()));

        let mut rows = conn
            .query(&sql, libsql::params_from_iter(params))
            .await
            .map_err(|e| WenlanError::VectorDb(format!("list_memories: {}", e)))?;

        let mut items = Vec::new();
        while let Some(row) = rows
            .next()
            .await
            .map_err(|e| WenlanError::VectorDb(e.to_string()))?
        {
            items.push(MemoryItem {
                source_id: row.get::<String>(0).unwrap_or_default(),
                title: row.get::<String>(1).unwrap_or_default(),
                content: row.get::<String>(2).unwrap_or_default(),
                summary: row.get::<Option<String>>(3).unwrap_or(None),
                memory_type: row.get::<Option<String>>(4).unwrap_or(None),
                space: row.get::<Option<String>>(5).unwrap_or(None),
                source_agent: row.get::<Option<String>>(6).unwrap_or(None),
                confidence: row.get::<Option<f64>>(7).unwrap_or(None).map(|v| v as f32),
                confirmed: row.get::<i64>(8).unwrap_or(0) != 0,
                stability: row.get::<Option<String>>(9).unwrap_or(None),
                pinned: row.get::<i64>(10).unwrap_or(0) != 0,
                supersedes: row.get::<Option<String>>(11).unwrap_or(None),
                last_modified: row.get::<i64>(12).unwrap_or(0),
                chunk_count: row.get::<u64>(13).unwrap_or(0),
                entity_id: row.get::<Option<String>>(14).unwrap_or(None),
                quality: row.get::<Option<String>>(15).unwrap_or(None),
                is_recap: row.get::<i64>(16).unwrap_or(0) != 0,
                enrichment_status: row.get::<String>(17).unwrap_or_else(|_| "raw".to_string()),
                supersede_mode: row.get::<String>(18).unwrap_or_else(|_| "hide".to_string()),
                structured_fields: row.get::<Option<String>>(19).unwrap_or(None),
                retrieval_cue: row.get::<Option<String>>(20).unwrap_or(None),
                access_count: row.get::<u64>(21).unwrap_or(0),
                source_text: row.get::<Option<String>>(22).unwrap_or(None),
                version: row.get::<i64>(23).unwrap_or(1),
                changelog: row.get::<Option<String>>(24).unwrap_or(None),
                pending_revision: false,
                merged_from: None,
            });
        }
        Ok(items)
    }

    /// Fetch a single memory by source_id, aggregating its memories.
    pub async fn get_memory_detail(
        &self,
        source_id: &str,
    ) -> Result<Option<MemoryItem>, WenlanError> {
        let conn = self.conn.lock().await;
        let sql = "SELECT source_id, title,
                    GROUP_CONCAT(content, '\n') as content,
                    MAX(summary) as summary,
                    MAX(memory_type) as memory_type,
                    MAX(space) as space,
                    MAX(source_agent) as source_agent,
                    MAX(confidence) as confidence,
                    MAX(confirmed) as confirmed,
                    MAX(stability) as stability,
                    MAX(pinned) as pinned,
                    MAX(supersedes) as supersedes,
                    MAX(last_modified) as last_modified,
                    COUNT(*) as chunk_count,
                    MAX(entity_id) as entity_id,
                    MAX(quality) as quality,
                    MAX(is_recap) as is_recap,
                    (SELECT CASE
                        WHEN COUNT(es.source_id) = 0 THEN 'raw'
                        WHEN SUM(CASE WHEN es.status = 'failed' OR es.status = 'abandoned' THEN 1 ELSE 0 END) = 0 THEN 'enriched'
                        WHEN SUM(CASE WHEN es.status IN ('ok','skipped') THEN 1 ELSE 0 END) = 0 THEN 'enrichment_failed'
                        ELSE 'enrichment_partial'
                    END FROM enrichment_steps es WHERE es.source_id = memories.source_id) AS enrichment_status,
                    MAX(supersede_mode) as supersede_mode,
                    MAX(structured_fields) as structured_fields,
                    MAX(retrieval_cue) as retrieval_cue,
                    SUM(access_count) as access_count,
                    MAX(source_text) as source_text,
                    MAX(version) as version,
                    MAX(changelog) as changelog
             FROM memories
             WHERE pending_revision = 0
               AND source != 'episode'
               AND source_id = ?1
             GROUP BY source_id";

        let mut rows = conn
            .query(sql, libsql::params![source_id])
            .await
            .map_err(|e| WenlanError::VectorDb(format!("get_memory_detail: {}", e)))?;

        if let Some(row) = rows
            .next()
            .await
            .map_err(|e| WenlanError::VectorDb(e.to_string()))?
        {
            Ok(Some(MemoryItem {
                source_id: row.get::<String>(0).unwrap_or_default(),
                title: row.get::<String>(1).unwrap_or_default(),
                content: row.get::<String>(2).unwrap_or_default(),
                summary: row.get::<Option<String>>(3).unwrap_or(None),
                memory_type: row.get::<Option<String>>(4).unwrap_or(None),
                space: row.get::<Option<String>>(5).unwrap_or(None),
                source_agent: row.get::<Option<String>>(6).unwrap_or(None),
                confidence: row.get::<Option<f64>>(7).unwrap_or(None).map(|v| v as f32),
                confirmed: row.get::<i64>(8).unwrap_or(0) != 0,
                stability: row.get::<Option<String>>(9).unwrap_or(None),
                pinned: row.get::<i64>(10).unwrap_or(0) != 0,
                supersedes: row.get::<Option<String>>(11).unwrap_or(None),
                last_modified: row.get::<i64>(12).unwrap_or(0),
                chunk_count: row.get::<u64>(13).unwrap_or(0),
                entity_id: row.get::<Option<String>>(14).unwrap_or(None),
                quality: row.get::<Option<String>>(15).unwrap_or(None),
                is_recap: row.get::<i64>(16).unwrap_or(0) != 0,
                enrichment_status: row.get::<String>(17).unwrap_or_else(|_| "raw".to_string()),
                supersede_mode: row.get::<String>(18).unwrap_or_else(|_| "hide".to_string()),
                structured_fields: row.get::<Option<String>>(19).unwrap_or(None),
                retrieval_cue: row.get::<Option<String>>(20).unwrap_or(None),
                access_count: row.get::<u64>(21).unwrap_or(0),
                source_text: row.get::<Option<String>>(22).unwrap_or(None),
                version: row.get::<i64>(23).unwrap_or(1),
                changelog: row.get::<Option<String>>(24).unwrap_or(None),
                pending_revision: false,
                merged_from: None,
            }))
        } else {
            Ok(None)
        }
    }

    /// Fetch multiple memories by source_id in a single query.
    /// Returns only the source_ids that exist; missing ids are silently omitted.
    /// Preserves input order.
    pub async fn get_memories_by_source_ids(
        &self,
        source_ids: &[String],
    ) -> Result<Vec<MemoryItem>, WenlanError> {
        if source_ids.is_empty() {
            return Ok(vec![]);
        }
        let placeholders = source_ids
            .iter()
            .enumerate()
            .map(|(i, _)| format!("?{}", i + 1))
            .collect::<Vec<_>>()
            .join(",");
        let sql = format!(
            "SELECT source_id, title,
                GROUP_CONCAT(content, '\n') as content,
                MAX(summary) as summary,
                MAX(memory_type) as memory_type,
                MAX(space) as space,
                MAX(source_agent) as source_agent,
                MAX(confidence) as confidence,
                MAX(confirmed) as confirmed,
                MAX(stability) as stability,
                MAX(pinned) as pinned,
                MAX(supersedes) as supersedes,
                MAX(last_modified) as last_modified,
                COUNT(*) as chunk_count,
                MAX(entity_id) as entity_id,
                MAX(quality) as quality,
                MAX(is_recap) as is_recap,
                (SELECT CASE
                    WHEN COUNT(es.source_id) = 0 THEN 'raw'
                    WHEN SUM(CASE WHEN es.status = 'failed' OR es.status = 'abandoned' THEN 1 ELSE 0 END) = 0 THEN 'enriched'
                    WHEN SUM(CASE WHEN es.status IN ('ok','skipped') THEN 1 ELSE 0 END) = 0 THEN 'enrichment_failed'
                    ELSE 'enrichment_partial'
                END FROM enrichment_steps es WHERE es.source_id = memories.source_id) AS enrichment_status,
                MAX(supersede_mode) as supersede_mode,
                MAX(structured_fields) as structured_fields,
                MAX(retrieval_cue) as retrieval_cue,
                SUM(access_count) as access_count,
                MAX(source_text) as source_text,
                MAX(version) as version,
                MAX(changelog) as changelog
             FROM memories
             WHERE pending_revision = 0
               AND source != 'episode'
               AND source_id IN ({placeholders})
             GROUP BY source_id"
        );
        let conn = self.conn.lock().await;
        let params: Vec<libsql::Value> = source_ids
            .iter()
            .map(|id| libsql::Value::Text(id.clone()))
            .collect();
        let mut rows = conn
            .query(&sql, libsql::params_from_iter(params))
            .await
            .map_err(|e| WenlanError::VectorDb(format!("get_memories_by_source_ids: {e}")))?;

        // Build a map keyed by source_id, then re-order to match input order.
        let mut map: std::collections::HashMap<String, MemoryItem> =
            std::collections::HashMap::new();
        while let Some(row) = rows
            .next()
            .await
            .map_err(|e| WenlanError::VectorDb(e.to_string()))?
        {
            let item = MemoryItem {
                source_id: row.get::<String>(0).unwrap_or_default(),
                title: row.get::<String>(1).unwrap_or_default(),
                content: row.get::<String>(2).unwrap_or_default(),
                summary: row.get::<Option<String>>(3).unwrap_or(None),
                memory_type: row.get::<Option<String>>(4).unwrap_or(None),
                space: row.get::<Option<String>>(5).unwrap_or(None),
                source_agent: row.get::<Option<String>>(6).unwrap_or(None),
                confidence: row.get::<Option<f64>>(7).unwrap_or(None).map(|v| v as f32),
                confirmed: row.get::<i64>(8).unwrap_or(0) != 0,
                stability: row.get::<Option<String>>(9).unwrap_or(None),
                pinned: row.get::<i64>(10).unwrap_or(0) != 0,
                supersedes: row.get::<Option<String>>(11).unwrap_or(None),
                last_modified: row.get::<i64>(12).unwrap_or(0),
                chunk_count: row.get::<u64>(13).unwrap_or(0),
                entity_id: row.get::<Option<String>>(14).unwrap_or(None),
                quality: row.get::<Option<String>>(15).unwrap_or(None),
                is_recap: row.get::<i64>(16).unwrap_or(0) != 0,
                enrichment_status: row.get::<String>(17).unwrap_or_else(|_| "raw".to_string()),
                supersede_mode: row.get::<String>(18).unwrap_or_else(|_| "hide".to_string()),
                structured_fields: row.get::<Option<String>>(19).unwrap_or(None),
                retrieval_cue: row.get::<Option<String>>(20).unwrap_or(None),
                access_count: row.get::<u64>(21).unwrap_or(0),
                source_text: row.get::<Option<String>>(22).unwrap_or(None),
                version: row.get::<i64>(23).unwrap_or(1),
                changelog: row.get::<Option<String>>(24).unwrap_or(None),
                pending_revision: false,
                merged_from: None,
            };
            map.insert(item.source_id.clone(), item);
        }
        // Return in input order, skipping missing ids.
        let items = source_ids.iter().filter_map(|id| map.remove(id)).collect();
        Ok(items)
    }

    /// Load confirmed memories of a specific type, excluding superseded ones.
    /// Optionally filter by space when `space_filter` is `Some`.
    pub async fn load_memories_by_type(
        &self,
        memory_type: &str,
        limit: usize,
        space_filter: Option<&str>,
    ) -> Result<Vec<MemoryItem>, WenlanError> {
        let conn = self.conn.lock().await;
        let supersedes_exclusion = "AND pending_revision = 0 AND source_id NOT IN (SELECT supersedes FROM memories WHERE supersedes IS NOT NULL AND pending_revision = 0 AND source = 'memory' GROUP BY supersedes)";

        let space_clause = match space_filter {
            Some("uncategorized") => "AND space IS NULL",
            Some(_) => "AND space = ?3",
            None => "",
        };

        let sql = format!(
            "SELECT source_id, MAX(title) as title,
                    GROUP_CONCAT(content, '\n') as content,
                    MAX(summary) as summary,
                    MAX(memory_type) as memory_type,
                    MAX(space) as space,
                    MAX(source_agent) as source_agent,
                    MAX(confidence) as confidence,
                    MAX(confirmed) as confirmed,
                    MAX(stability) as stability,
                    MAX(pinned) as pinned,
                    MAX(supersedes) as supersedes,
                    MAX(last_modified) as last_modified,
                    COUNT(*) as chunk_count,
                    MAX(entity_id) as entity_id,
                    MAX(quality) as quality,
                    MAX(is_recap) as is_recap,
                    (SELECT CASE
                        WHEN COUNT(es.source_id) = 0 THEN 'raw'
                        WHEN SUM(CASE WHEN es.status = 'failed' OR es.status = 'abandoned' THEN 1 ELSE 0 END) = 0 THEN 'enriched'
                        WHEN SUM(CASE WHEN es.status IN ('ok','skipped') THEN 1 ELSE 0 END) = 0 THEN 'enrichment_failed'
                        ELSE 'enrichment_partial'
                    END FROM enrichment_steps es WHERE es.source_id = memories.source_id) AS enrichment_status,
                    MAX(supersede_mode) as supersede_mode,
                    MAX(structured_fields) as structured_fields,
                    MAX(retrieval_cue) as retrieval_cue,
                    SUM(access_count) as access_count,
                    MAX(source_text) as source_text,
                    MAX(version) as version,
                    MAX(changelog) as changelog
             FROM memories
             WHERE source = 'memory' AND memory_type = ?1 AND confirmed != 0
             {} {}
             GROUP BY source_id
             ORDER BY last_modified DESC
             LIMIT ?2",
            supersedes_exclusion, space_clause
        );

        let mut rows = match space_filter {
            Some("uncategorized") | None => {
                conn.query(&sql, libsql::params![memory_type.to_string(), limit as i64])
                    .await
            }
            Some(space) => {
                conn.query(
                    &sql,
                    libsql::params![memory_type.to_string(), limit as i64, space.to_string()],
                )
                .await
            }
        }
        .map_err(|e| WenlanError::VectorDb(format!("load_memories_by_type: {}", e)))?;

        let mut items = Vec::new();
        while let Some(row) = rows
            .next()
            .await
            .map_err(|e| WenlanError::VectorDb(e.to_string()))?
        {
            items.push(MemoryItem {
                source_id: row.get::<String>(0).unwrap_or_default(),
                title: row.get::<String>(1).unwrap_or_default(),
                content: row.get::<String>(2).unwrap_or_default(),
                summary: row.get::<Option<String>>(3).unwrap_or(None),
                memory_type: row.get::<Option<String>>(4).unwrap_or(None),
                space: row.get::<Option<String>>(5).unwrap_or(None),
                source_agent: row.get::<Option<String>>(6).unwrap_or(None),
                confidence: row.get::<Option<f64>>(7).unwrap_or(None).map(|v| v as f32),
                confirmed: row.get::<i64>(8).unwrap_or(0) != 0,
                stability: row.get::<Option<String>>(9).unwrap_or(None),
                pinned: row.get::<i64>(10).unwrap_or(0) != 0,
                supersedes: row.get::<Option<String>>(11).unwrap_or(None),
                last_modified: row.get::<i64>(12).unwrap_or(0),
                chunk_count: row.get::<u64>(13).unwrap_or(0),
                entity_id: row.get::<Option<String>>(14).unwrap_or(None),
                quality: row.get::<Option<String>>(15).unwrap_or(None),
                is_recap: row.get::<i64>(16).unwrap_or(0) != 0,
                enrichment_status: row.get::<String>(17).unwrap_or_else(|_| "raw".to_string()),
                supersede_mode: row.get::<String>(18).unwrap_or_else(|_| "hide".to_string()),
                structured_fields: row.get::<Option<String>>(19).unwrap_or(None),
                retrieval_cue: row.get::<Option<String>>(20).unwrap_or(None),
                access_count: row.get::<u64>(21).unwrap_or(0),
                source_text: row.get::<Option<String>>(22).unwrap_or(None),
                version: row.get::<i64>(23).unwrap_or(1),
                changelog: row.get::<Option<String>>(24).unwrap_or(None),
                pending_revision: false,
                merged_from: None,
            });
        }
        Ok(items)
    }

    /// Load decision memories for the timeline view.
    /// Filters to `source = 'memory' AND memory_type = 'decision' AND chunk_index = 0`.
    /// Returns full `MemoryItem` rows with `structured_fields` for expanded view.
    pub async fn load_decisions(
        &self,
        space: Option<&str>,
        limit: usize,
    ) -> Result<Vec<MemoryItem>, WenlanError> {
        let conn = self.conn.lock().await;
        let supersedes_exclusion = "AND pending_revision = 0 AND source_id NOT IN (SELECT supersedes FROM memories WHERE supersedes IS NOT NULL AND pending_revision = 0 AND source = 'memory' GROUP BY supersedes)";

        let space_clause = if space.is_some() {
            "AND space = ?2"
        } else {
            ""
        };

        let sql = format!(
            "SELECT source_id, MAX(title) as title,
                    GROUP_CONCAT(content, '\n') as content,
                    MAX(summary) as summary,
                    MAX(memory_type) as memory_type,
                    MAX(space) as space,
                    MAX(source_agent) as source_agent,
                    MAX(confidence) as confidence,
                    MAX(confirmed) as confirmed,
                    MAX(stability) as stability,
                    MAX(pinned) as pinned,
                    MAX(supersedes) as supersedes,
                    MAX(last_modified) as last_modified,
                    COUNT(*) as chunk_count,
                    MAX(entity_id) as entity_id,
                    MAX(quality) as quality,
                    MAX(is_recap) as is_recap,
                    (SELECT CASE
                        WHEN COUNT(es.source_id) = 0 THEN 'raw'
                        WHEN SUM(CASE WHEN es.status = 'failed' OR es.status = 'abandoned' THEN 1 ELSE 0 END) = 0 THEN 'enriched'
                        WHEN SUM(CASE WHEN es.status IN ('ok','skipped') THEN 1 ELSE 0 END) = 0 THEN 'enrichment_failed'
                        ELSE 'enrichment_partial'
                    END FROM enrichment_steps es WHERE es.source_id = memories.source_id) AS enrichment_status,
                    MAX(supersede_mode) as supersede_mode,
                    MAX(structured_fields) as structured_fields,
                    MAX(retrieval_cue) as retrieval_cue,
                    SUM(access_count) as access_count,
                    MAX(source_text) as source_text,
                    MAX(version) as version,
                    MAX(changelog) as changelog
             FROM memories
             WHERE source = 'memory' AND memory_type = 'decision' AND chunk_index = 0 AND confirmed != 0
             {} {}
             GROUP BY source_id
             ORDER BY last_modified DESC
             LIMIT ?1",
            supersedes_exclusion, space_clause
        );

        let mut rows = if let Some(d) = space {
            conn.query(&sql, libsql::params![limit as i64, d.to_string()])
                .await
        } else {
            conn.query(&sql, libsql::params![limit as i64]).await
        }
        .map_err(|e| WenlanError::VectorDb(format!("load_decisions: {}", e)))?;

        let mut items = Vec::new();
        while let Some(row) = rows
            .next()
            .await
            .map_err(|e| WenlanError::VectorDb(e.to_string()))?
        {
            items.push(MemoryItem {
                source_id: row.get::<String>(0).unwrap_or_default(),
                title: row.get::<String>(1).unwrap_or_default(),
                content: row.get::<String>(2).unwrap_or_default(),
                summary: row.get::<Option<String>>(3).unwrap_or(None),
                memory_type: row.get::<Option<String>>(4).unwrap_or(None),
                space: row.get::<Option<String>>(5).unwrap_or(None),
                source_agent: row.get::<Option<String>>(6).unwrap_or(None),
                confidence: row.get::<Option<f64>>(7).unwrap_or(None).map(|v| v as f32),
                confirmed: row.get::<i64>(8).unwrap_or(0) != 0,
                stability: row.get::<Option<String>>(9).unwrap_or(None),
                pinned: row.get::<i64>(10).unwrap_or(0) != 0,
                supersedes: row.get::<Option<String>>(11).unwrap_or(None),
                last_modified: row.get::<i64>(12).unwrap_or(0),
                chunk_count: row.get::<u64>(13).unwrap_or(0),
                entity_id: row.get::<Option<String>>(14).unwrap_or(None),
                quality: row.get::<Option<String>>(15).unwrap_or(None),
                is_recap: row.get::<i64>(16).unwrap_or(0) != 0,
                enrichment_status: row.get::<String>(17).unwrap_or_else(|_| "raw".to_string()),
                supersede_mode: row.get::<String>(18).unwrap_or_else(|_| "hide".to_string()),
                structured_fields: row.get::<Option<String>>(19).unwrap_or(None),
                retrieval_cue: row.get::<Option<String>>(20).unwrap_or(None),
                access_count: row.get::<u64>(21).unwrap_or(0),
                source_text: row.get::<Option<String>>(22).unwrap_or(None),
                version: row.get::<i64>(23).unwrap_or(1),
                changelog: row.get::<Option<String>>(24).unwrap_or(None),
                pending_revision: false,
                merged_from: None,
            });
        }
        Ok(items)
    }

    /// List distinct spaces that have decision memories.
    pub async fn list_decision_spaces(&self) -> Result<Vec<String>, WenlanError> {
        let conn = self.conn.lock().await;
        let sql = "SELECT DISTINCT space FROM memories WHERE source = 'memory' AND memory_type = 'decision' AND space IS NOT NULL ORDER BY space";
        let mut rows = conn
            .query(sql, libsql::params![])
            .await
            .map_err(|e| WenlanError::VectorDb(format!("list_decision_spaces: {}", e)))?;

        let mut spaces = Vec::new();
        while let Some(row) = rows
            .next()
            .await
            .map_err(|e| WenlanError::VectorDb(e.to_string()))?
        {
            if let Ok(d) = row.get::<String>(0) {
                spaces.push(d);
            }
        }
        Ok(spaces)
    }

    /// List documents matching structured filters, deduped by source_id.
    /// All filter values are passed as parameterized queries to prevent SQL injection.
    pub async fn list_filtered(
        &self,
        source: Option<&str>,
        memory_type: Option<&str>,
        space: Option<&str>,
        limit: usize,
    ) -> Result<Vec<IndexedFileInfo>, WenlanError> {
        self.list_filtered_confirmed(source, memory_type, space, None, limit)
            .await
    }

    /// Like `list_filtered` but with an optional `confirmed` predicate.
    pub async fn list_filtered_confirmed(
        &self,
        source: Option<&str>,
        memory_type: Option<&str>,
        space: Option<&str>,
        confirmed: Option<bool>,
        limit: usize,
    ) -> Result<Vec<IndexedFileInfo>, WenlanError> {
        let conn = self.conn.lock().await;

        let mut conditions = Vec::new();
        let mut params: Vec<libsql::Value> = Vec::new();
        let mut idx = 1;

        if let Some(s) = source {
            conditions.push(format!("source = ?{}", idx));
            params.push(s.to_string().into());
            idx += 1;
        }
        if let Some(mt) = memory_type {
            conditions.push(format!("memory_type = ?{}", idx));
            params.push(mt.to_string().into());
            idx += 1;
        }
        if let Some(d) = space {
            if d == "uncategorized" {
                conditions.push("space IS NULL".to_string());
            } else {
                conditions.push(format!("space = ?{}", idx));
                params.push(d.to_string().into());
                idx += 1;
            }
        }
        if let Some(c) = confirmed {
            if c {
                conditions.push(format!("confirmed = ?{}", idx));
                params.push(1i64.into());
                idx += 1;
            } else {
                // NULL means "not yet confirmed" — include both explicit 0 and NULL.
                // Also exclude archived supersedes and recap rows to match the
                // same set returned by list_unconfirmed_memories.
                conditions.push("(confirmed = 0 OR confirmed IS NULL)".to_string());
                conditions.push(
                    "(supersede_mode IS NULL OR supersede_mode NOT IN ('archive', 'evicted'))"
                        .to_string(),
                );
                conditions.push("(is_recap IS NULL OR is_recap != 1)".to_string());
            }
        }

        // Exclude superseded memories and pending revisions
        conditions.push("pending_revision = 0".to_string());
        // T2: never list verbatim episode rows in the filtered file view.
        conditions.push("source != 'episode'".to_string());
        conditions.push("source_id NOT IN (SELECT supersedes FROM memories WHERE supersedes IS NOT NULL AND pending_revision = 0 AND source = 'memory' GROUP BY supersedes)".to_string());

        let where_clause = if conditions.is_empty() {
            String::new()
        } else {
            format!("WHERE {}", conditions.join(" AND "))
        };

        params.push((limit as i64).into());
        let limit_param = idx;

        let sql = format!(
            "SELECT source_id, MAX(title) as title, MAX(source) as source,
                    MAX(url) as url, COUNT(*) as chunk_count,
                    MAX(last_modified) as last_modified, MAX(summary) as summary,
                    MAX(memory_type), MAX(space), MAX(source_agent),
                    MAX(CAST(confidence AS REAL)), MAX(confirmed), MAX(pinned),
                    MAX(created_at) as created_at,
                    MAX(content) as content
             FROM memories
             {}
             GROUP BY source_id
             ORDER BY MAX(last_modified) DESC
             LIMIT ?{}",
            where_clause, limit_param
        );

        let mut rows = conn
            .query(&sql, libsql::params_from_iter(params))
            .await
            .map_err(|e| WenlanError::VectorDb(format!("list_filtered: {}", e)))?;

        let mut results = Vec::new();
        while let Ok(Some(row)) = rows.next().await {
            results.push(IndexedFileInfo {
                source_id: row.get::<String>(0).unwrap_or_default(),
                title: row.get::<String>(1).unwrap_or_default(),
                source: row.get::<String>(2).unwrap_or_default(),
                url: row.get::<Option<String>>(3).unwrap_or(None),
                chunk_count: row.get::<i64>(4).unwrap_or(0) as u64,
                last_modified: row.get::<i64>(5).unwrap_or(0),
                summary: row.get::<Option<String>>(6).unwrap_or(None),
                processing: false,
                memory_type: row.get::<Option<String>>(7).unwrap_or(None),
                space: row.get::<Option<String>>(8).unwrap_or(None),
                source_agent: row.get::<Option<String>>(9).unwrap_or(None),
                confidence: row.get::<Option<f64>>(10).unwrap_or(None).map(|v| v as f32),
                confirmed: row.get::<Option<i64>>(11).unwrap_or(None).map(|v| v != 0),
                stability: None, // not fetched in list_filtered aggregate query
                pinned: row.get::<i64>(12).unwrap_or(0) != 0,
                created_at: row.get::<Option<i64>>(13).unwrap_or(None).unwrap_or(0),
                content: row
                    .get::<Option<String>>(14)
                    .unwrap_or(None)
                    .unwrap_or_default(),
            });
        }

        Ok(results)
    }

    // ===== Knowledge Graph Methods =====

    /// Create a new entity in the knowledge graph (simplified — no embedding, no source_agent/confidence).
    pub async fn create_entity(
        &self,
        name: &str,
        entity_type: &str,
        space: Option<&str>,
    ) -> Result<String, WenlanError> {
        let id = uuid::Uuid::new_v4().to_string();
        let now = chrono::Utc::now().timestamp();

        let conn = self.conn.lock().await;
        conn.execute(
            "INSERT INTO entities (id, name, entity_type, space, confirmed, created_at, updated_at)
             VALUES (?1, ?2, ?3, ?4, 0, ?5, ?5)",
            libsql::params![
                id.clone(),
                name.to_string(),
                entity_type.to_string(),
                space.map(|d| d.to_string()),
                now
            ],
        )
        .await
        .map_err(|e| WenlanError::VectorDb(format!("create_entity: {}", e)))?;

        Ok(id)
    }

    /// Store a new entity in the knowledge graph.
    pub async fn store_entity(
        &self,
        name: &str,
        entity_type: &str,
        space: Option<&str>,
        source_agent: Option<&str>,
        confidence: Option<f32>,
    ) -> Result<String, WenlanError> {
        let id = uuid::Uuid::new_v4().to_string();
        let now = chrono::Utc::now().timestamp();

        let embedding = self.get_or_compute_embedding(name)?;
        let vec_str = Self::vec_to_sql(&embedding);

        let conn = self.conn.lock().await;
        conn.execute(
            "INSERT INTO entities (id, name, entity_type, space, source_agent, confidence,
                confirmed, created_at, updated_at, embedding)
             VALUES (?1, ?2, ?3, ?4, ?5, ?6, 0, ?7, ?7, vector32(?8))",
            libsql::params![
                id.clone(),
                name.to_string(),
                entity_type.to_string(),
                space
                    .map(|s| libsql::Value::Text(s.to_string()))
                    .unwrap_or(libsql::Value::Null),
                source_agent
                    .map(|s| libsql::Value::Text(s.to_string()))
                    .unwrap_or(libsql::Value::Null),
                confidence
                    .map(|v| libsql::Value::Real(v as f64))
                    .unwrap_or(libsql::Value::Null),
                now,
                vec_str
            ],
        )
        .await
        .map_err(|e| WenlanError::VectorDb(format!("store_entity: {}", e)))?;

        // Auto-create a self-alias for the entity name (lowercase).
        conn.execute(
            "INSERT OR IGNORE INTO entity_aliases (alias_name, canonical_entity_id, created_at, source) VALUES (?1, ?2, unixepoch(), 'auto')",
            libsql::params![name.to_lowercase(), id.clone()],
        )
        .await
        .map_err(|e| WenlanError::VectorDb(format!("store_entity alias: {}", e)))?;

        Ok(id)
    }

    /// Persist the LSH band keys for an entity into `entity_minhash_bands`
    /// (T16). Only high-entropy names are indexed (gated by the caller) so the
    /// table stays small. `INSERT OR IGNORE` keeps the call idempotent; the
    /// whole batch runs inside one BEGIN/COMMIT (batch-SQL rule).
    pub async fn store_entity_minhash_bands(
        &self,
        entity_id: &str,
        band_keys: &[u64],
    ) -> Result<(), WenlanError> {
        if band_keys.is_empty() {
            return Ok(());
        }
        let conn = self.conn.lock().await;
        conn.execute("BEGIN TRANSACTION", ())
            .await
            .map_err(|e| WenlanError::VectorDb(format!("store_minhash begin: {e}")))?;
        let result: Result<(), WenlanError> = async {
            for &key in band_keys {
                // libSQL INTEGER is i64; band keys are u64 LSH hashes. Reinterpret
                // the bit pattern (i64::from_ne_bytes) so the round-trip is exact;
                // query_entities_by_band applies the inverse on the way out.
                let signed = key as i64;
                conn.execute(
                    "INSERT OR IGNORE INTO entity_minhash_bands (band_key, entity_id) VALUES (?1, ?2)",
                    libsql::params![signed, entity_id.to_string()],
                )
                .await
                .map_err(|e| WenlanError::VectorDb(format!("store_minhash insert: {e}")))?;
            }
            Ok(())
        }
        .await;
        match result {
            Ok(()) => {
                conn.execute("COMMIT", ())
                    .await
                    .map_err(|e| WenlanError::VectorDb(format!("store_minhash commit: {e}")))?;
                Ok(())
            }
            Err(e) => {
                if let Err(rb) = conn.execute("ROLLBACK", ()).await {
                    log::error!("store_entity_minhash_bands ROLLBACK failed: {rb}");
                }
                Err(e)
            }
        }
    }

    /// Return the distinct entity ids that share at least one of `band_keys`
    /// in `entity_minhash_bands` (T16 LSH candidate lookup). Placeholders are
    /// parameterized -- band keys are never interpolated into the SQL string.
    pub async fn query_entities_by_band(
        &self,
        band_keys: &[u64],
    ) -> Result<Vec<String>, WenlanError> {
        if band_keys.is_empty() {
            return Ok(Vec::new());
        }
        let placeholders = (1..=band_keys.len())
            .map(|i| format!("?{i}"))
            .collect::<Vec<_>>()
            .join(", ");
        let sql = format!(
            "SELECT DISTINCT entity_id FROM entity_minhash_bands WHERE band_key IN ({placeholders})"
        );
        let params: Vec<libsql::Value> = band_keys
            .iter()
            .map(|&k| libsql::Value::Integer(k as i64))
            .collect();
        let conn = self.conn.lock().await;
        let mut rows = conn
            .query(&sql, libsql::params_from_iter(params))
            .await
            .map_err(|e| WenlanError::VectorDb(format!("query_minhash: {e}")))?;
        let mut ids = Vec::new();
        while let Some(row) = rows
            .next()
            .await
            .map_err(|e| WenlanError::VectorDb(format!("query_minhash row: {e}")))?
        {
            if let Ok(id) = row.get::<String>(0) {
                ids.push(id);
            }
        }
        Ok(ids)
    }

    /// Remove all band rows for an entity (explicit cleanup on merge-loser
    /// delete; complements the ON DELETE CASCADE FK in case it is not honored).
    pub async fn delete_entity_minhash_bands(&self, entity_id: &str) -> Result<(), WenlanError> {
        let conn = self.conn.lock().await;
        conn.execute(
            "DELETE FROM entity_minhash_bands WHERE entity_id = ?1",
            libsql::params![entity_id.to_string()],
        )
        .await
        .map_err(|e| WenlanError::VectorDb(format!("delete_minhash: {e}")))?;
        Ok(())
    }

    /// Lightweight `(name, entity_type)` fetch for a single entity id. Used by
    /// the T16 MinHash cascade to apply the same-type guard on band candidates
    /// without loading the full `EntityDetail` (observations etc.). Returns
    /// `None` if the id does not exist.
    pub async fn get_entity_name_type(
        &self,
        entity_id: &str,
    ) -> Result<Option<(String, String)>, WenlanError> {
        let conn = self.conn.lock().await;
        let mut rows = conn
            .query(
                "SELECT name, entity_type FROM entities WHERE id = ?1",
                libsql::params![entity_id.to_string()],
            )
            .await
            .map_err(|e| WenlanError::VectorDb(format!("get_entity_name_type: {e}")))?;
        if let Some(row) = rows
            .next()
            .await
            .map_err(|e| WenlanError::VectorDb(format!("get_entity_name_type row: {e}")))?
        {
            let name: String = row.get(0).unwrap_or_default();
            let etype: String = row.get(1).unwrap_or_default();
            Ok(Some((name, etype)))
        } else {
            Ok(None)
        }
    }

    /// T16 "Step 2.5": deterministic MinHash/LSH near-dedup resolution.
    ///
    /// SHARED by `post_write::create_entity` and `importer::resolve_entity_bulk`
    /// so the agent and bulk paths can never diverge (Risk #4). Caller must have
    /// already checked `entity_minhash_enabled()`. Returns `Some(existing_id)`
    /// when a same-type band candidate confirms at exact Jaccard >= 0.9 (the
    /// caller then records a "minhash" alias and resolves to that id); `None`
    /// when the name is low-entropy/short or no candidate confirms (caller falls
    /// through to the vector step).
    pub async fn minhash_resolve_candidate(
        &self,
        name: &str,
        entity_type: &str,
    ) -> Result<Option<String>, WenlanError> {
        use crate::retrieval::dedup;
        // Entropy gate: short/low-entropy names (3-char acronyms) are punted to
        // the vector step so the fuzzy layer never over-merges distinct names.
        if !dedup::has_high_entropy(name) {
            return Ok(None);
        }
        let bands = dedup::name_band_keys(name);
        let candidates = self.query_entities_by_band(&bands).await?;
        for cand_id in candidates {
            let Some((cand_name, cand_type)) = self.get_entity_name_type(&cand_id).await? else {
                continue;
            };
            // Same-type guard: never auto-merge across entity types.
            if !cand_type.eq_ignore_ascii_case(entity_type) {
                continue;
            }
            if dedup::name_jaccard(name, &cand_name) >= dedup::FUZZY_JACCARD_THRESHOLD {
                return Ok(Some(cand_id));
            }
        }
        Ok(None)
    }

    /// Index a newly created entity's band keys IFF it is high-entropy (T16).
    /// Keeps `entity_minhash_bands` small by skipping short/low-entropy names.
    /// Best-effort: caller has already checked `entity_minhash_enabled()`.
    pub async fn index_entity_minhash_if_eligible(
        &self,
        entity_id: &str,
        name: &str,
    ) -> Result<(), WenlanError> {
        use crate::retrieval::dedup;
        if !dedup::has_high_entropy(name) {
            return Ok(());
        }
        let bands = dedup::name_band_keys(name);
        self.store_entity_minhash_bands(entity_id, &bands).await
    }

    /// Resolve an entity ID from an alias (case-insensitive).
    pub async fn resolve_entity_by_alias(&self, name: &str) -> Result<Option<String>, WenlanError> {
        let conn = self.conn.lock().await;
        let mut rows = conn
            .query(
                "SELECT canonical_entity_id FROM entity_aliases WHERE alias_name = ?1",
                libsql::params![name.to_lowercase()],
            )
            .await
            .map_err(|e| WenlanError::VectorDb(format!("alias lookup: {}", e)))?;
        if let Some(row) = rows
            .next()
            .await
            .map_err(|e| WenlanError::VectorDb(format!("alias row: {}", e)))?
        {
            Ok(Some(row.get::<String>(0).unwrap()))
        } else {
            Ok(None)
        }
    }

    /// Add an alias entry for an entity.
    pub async fn add_entity_alias(
        &self,
        alias: &str,
        entity_id: &str,
        source: &str,
    ) -> Result<(), WenlanError> {
        let conn = self.conn.lock().await;
        conn.execute(
            "INSERT OR IGNORE INTO entity_aliases (alias_name, canonical_entity_id, created_at, source) VALUES (?1, ?2, unixepoch(), ?3)",
            libsql::params![alias.to_lowercase(), entity_id.to_string(), source.to_string()],
        )
        .await
        .map_err(|e| WenlanError::VectorDb(format!("add alias: {}", e)))?;
        Ok(())
    }

    /// Resolve a relation type string against the vocabulary (case-insensitive).
    /// Returns `Some(canonical)` if the input matches a canonical or an alias,
    /// `None` if the input is not in the vocabulary.
    pub async fn resolve_relation_type(
        &self,
        relation_type: &str,
    ) -> Result<Option<String>, WenlanError> {
        let lower = relation_type.to_lowercase();
        let conn = self.conn.lock().await;

        // Check if input is already a canonical key (canonicals are lowercase).
        let mut rows = conn
            .query(
                "SELECT canonical FROM relation_type_vocabulary WHERE canonical = ?1",
                libsql::params![lower.clone()],
            )
            .await
            .map_err(|e| {
                WenlanError::VectorDb(format!("resolve_relation_type canonical: {}", e))
            })?;
        if rows
            .next()
            .await
            .map_err(|e| WenlanError::VectorDb(format!("resolve_relation_type row: {}", e)))?
            .is_some()
        {
            return Ok(Some(lower));
        }
        drop(rows);

        // Scan aliases JSON arrays for a case-insensitive match.
        let mut rows = conn
            .query(
                "SELECT canonical, aliases FROM relation_type_vocabulary WHERE aliases IS NOT NULL",
                libsql::params![],
            )
            .await
            .map_err(|e| WenlanError::VectorDb(format!("resolve_relation_type aliases: {}", e)))?;
        while let Some(row) = rows
            .next()
            .await
            .map_err(|e| WenlanError::VectorDb(format!("resolve_relation_type alias row: {}", e)))?
        {
            let canonical = row.get::<String>(0).unwrap_or_default();
            let aliases_json = row.get::<String>(1).unwrap_or_default();
            if let Ok(serde_json::Value::Array(arr)) = serde_json::from_str(&aliases_json) {
                for v in &arr {
                    if let Some(alias) = v.as_str() {
                        if alias.to_lowercase() == lower {
                            return Ok(Some(canonical));
                        }
                    }
                }
            }
        }

        // Not found — not a vocabulary type.
        Ok(None)
    }

    /// Increment the usage count for a canonical relation type.
    pub async fn increment_relation_type_count(&self, canonical: &str) -> Result<(), WenlanError> {
        let conn = self.conn.lock().await;
        conn.execute(
            "UPDATE relation_type_vocabulary SET count = count + 1 WHERE canonical = ?1",
            libsql::params![canonical.to_string()],
        )
        .await
        .map_err(|e| WenlanError::VectorDb(format!("increment_relation_type_count: {}", e)))?;
        Ok(())
    }

    /// Search entities by exact name (case-insensitive).
    pub async fn search_entities_by_name(&self, name: &str) -> Result<Vec<Entity>, WenlanError> {
        let conn = self.conn.lock().await;
        let mut rows = conn
            .query(
                "SELECT id, name, entity_type, space, source_agent, confidence, confirmed, created_at, updated_at
                 FROM entities WHERE LOWER(name) = LOWER(?1)",
                libsql::params![name.to_string()],
            )
            .await
            .map_err(|e| WenlanError::VectorDb(format!("search_entities_by_name: {}", e)))?;

        let mut entities = Vec::new();
        while let Some(row) = rows
            .next()
            .await
            .map_err(|e| WenlanError::VectorDb(e.to_string()))?
        {
            entities.push(Entity {
                id: row.get::<String>(0).unwrap_or_default(),
                name: row.get::<String>(1).unwrap_or_default(),
                entity_type: row.get::<String>(2).unwrap_or_default(),
                space: row.get::<Option<String>>(3).unwrap_or(None),
                source_agent: row.get::<Option<String>>(4).unwrap_or(None),
                confidence: row.get::<Option<f64>>(5).unwrap_or(None).map(|v| v as f32),
                confirmed: row.get::<i64>(6).unwrap_or(0) != 0,
                created_at: row.get::<i64>(7).unwrap_or(0),
                updated_at: row.get::<i64>(8).unwrap_or(0),
            });
        }
        Ok(entities)
    }

    /// Refresh an entity's embedding by recomputing from the provided text.
    /// Also updates `embedding_updated_at` and `updated_at` timestamps.
    pub async fn refresh_entity_embedding(
        &self,
        entity_id: &str,
        text: &str,
    ) -> Result<(), WenlanError> {
        let embeddings = self.generate_embeddings(&[text.to_string()])?;
        if embeddings.is_empty() {
            return Err(WenlanError::VectorDb(
                "refresh_entity_embedding: empty embedding result".into(),
            ));
        }
        let vec_str = Self::vec_to_sql(&embeddings[0]);
        let now = chrono::Utc::now().timestamp();
        let conn = self.conn.lock().await;
        conn.execute(
            "UPDATE entities SET embedding = vector32(?1), embedding_updated_at = ?2, updated_at = ?2 WHERE id = ?3",
            libsql::params![vec_str, now, entity_id.to_string()],
        )
        .await
        .map_err(|e| WenlanError::VectorDb(format!("refresh_entity_embedding: {}", e)))?;
        Ok(())
    }

    /// Add an observation to an entity.
    pub async fn add_observation(
        &self,
        entity_id: &str,
        content: &str,
        source_agent: Option<&str>,
        confidence: Option<f32>,
    ) -> Result<String, WenlanError> {
        let id = uuid::Uuid::new_v4().to_string();
        let now = chrono::Utc::now().timestamp();

        let conn = self.conn.lock().await;
        conn.execute(
            "INSERT INTO observations (id, entity_id, content, source_agent, confidence, confirmed, created_at)
             VALUES (?1, ?2, ?3, ?4, ?5, 0, ?6)",
            libsql::params![
                id.clone(),
                entity_id.to_string(),
                content.to_string(),
                source_agent.map(|s| libsql::Value::Text(s.to_string())).unwrap_or(libsql::Value::Null),
                confidence.map(|v| libsql::Value::Real(v as f64)).unwrap_or(libsql::Value::Null),
                now
            ],
        )
        .await
        .map_err(|e| WenlanError::VectorDb(format!("add_observation: {}", e)))?;

        // Update entity's updated_at
        conn.execute(
            "UPDATE entities SET updated_at = ?1 WHERE id = ?2",
            libsql::params![now, entity_id.to_string()],
        )
        .await
        .ok(); // Best effort

        Ok(id)
    }

    /// Merge `alias_id` into `canonical_id`. Re-points all FK references, registers
    /// the alias name, cleans dangling alias-table rows, and deletes the alias entity.
    /// Idempotent: returns `Ok(())` if `alias_id` is already gone.
    pub async fn merge_entities(
        &self,
        canonical_id: &str,
        alias_id: &str,
    ) -> Result<(), WenlanError> {
        if canonical_id == alias_id {
            return Err(WenlanError::Validation(
                "merge_entities: canonical and alias are the same id".into(),
            ));
        }

        let conn = self.conn.lock().await;
        // Idempotency check: assumes single-writer daemon (no other process holds
        // a libSQL connection to this DB). Mutex<Connection> serializes within-process;
        // cross-process races are not defended against.
        let alias_exists: i64 = {
            let mut rows = conn
                .query(
                    "SELECT COUNT(*) FROM entities WHERE id = ?1",
                    libsql::params![alias_id],
                )
                .await
                .map_err(|e| WenlanError::VectorDb(format!("merge_entities count alias: {e}")))?;
            let row = rows
                .next()
                .await
                .map_err(|e| WenlanError::VectorDb(format!("merge_entities row: {e}")))?
                .ok_or_else(|| WenlanError::VectorDb("merge_entities: no count row".into()))?;
            row.get(0).unwrap_or(0)
        };
        if alias_exists == 0 {
            return Ok(());
        }

        let canonical_exists: i64 = {
            let mut rows = conn
                .query(
                    "SELECT COUNT(*) FROM entities WHERE id = ?1",
                    libsql::params![canonical_id],
                )
                .await
                .map_err(|e| {
                    WenlanError::VectorDb(format!("merge_entities count canonical: {e}"))
                })?;
            let row = rows
                .next()
                .await
                .map_err(|e| WenlanError::VectorDb(format!("merge_entities row: {e}")))?
                .ok_or_else(|| WenlanError::VectorDb("merge_entities: no count row".into()))?;
            row.get(0).unwrap_or(0)
        };
        if canonical_exists == 0 {
            return Err(WenlanError::NotFound(format!(
                "canonical entity {canonical_id} not found"
            )));
        }

        let alias_name: Option<String> = {
            let mut rows = conn
                .query(
                    "SELECT name FROM entities WHERE id = ?1",
                    libsql::params![alias_id],
                )
                .await
                .map_err(|e| WenlanError::VectorDb(format!("merge_entities read name: {e}")))?;
            let row = rows
                .next()
                .await
                .map_err(|e| WenlanError::VectorDb(format!("merge_entities row: {e}")))?;
            row.and_then(|r| r.get::<String>(0).ok())
        };

        // T16 type-promotion inputs: read the alias (loser) type and the
        // canonical (winner) type BEFORE the transaction so the in-txn UPDATE
        // can promote a generic canonical to the loser's concrete type. Only
        // generic -> concrete is ever applied (never concrete -> different
        // concrete), so the winner's identity is preserved.
        let alias_type: String = {
            let mut rows = conn
                .query(
                    "SELECT entity_type FROM entities WHERE id = ?1",
                    libsql::params![alias_id],
                )
                .await
                .map_err(|e| {
                    WenlanError::VectorDb(format!("merge_entities read alias type: {e}"))
                })?;
            rows.next()
                .await
                .map_err(|e| WenlanError::VectorDb(format!("merge_entities row: {e}")))?
                .and_then(|r| r.get::<String>(0).ok())
                .unwrap_or_default()
        };
        let canonical_type: String = {
            let mut rows = conn
                .query(
                    "SELECT entity_type FROM entities WHERE id = ?1",
                    libsql::params![canonical_id],
                )
                .await
                .map_err(|e| {
                    WenlanError::VectorDb(format!("merge_entities read canonical type: {e}"))
                })?;
            rows.next()
                .await
                .map_err(|e| WenlanError::VectorDb(format!("merge_entities row: {e}")))?
                .and_then(|r| r.get::<String>(0).ok())
                .unwrap_or_default()
        };
        // Generic types eligible for promotion (case-insensitive). Promote only
        // when canonical is generic AND alias is concrete.
        let is_generic = |t: &str| {
            matches!(
                t.trim().to_ascii_lowercase().as_str(),
                "entity" | "unknown" | ""
            )
        };
        let should_promote = is_generic(&canonical_type) && !is_generic(&alias_type);

        conn.execute("BEGIN TRANSACTION", ())
            .await
            .map_err(|e| WenlanError::VectorDb(format!("merge_entities begin: {e}")))?;

        let result: Result<(), WenlanError> = async {
            conn.execute(
                "UPDATE relations SET from_entity = ?1 WHERE from_entity = ?2",
                libsql::params![canonical_id, alias_id],
            )
            .await
            .map_err(|e| WenlanError::VectorDb(format!("merge_entities rel.from: {e}")))?;

            conn.execute(
                "UPDATE relations SET to_entity = ?1 WHERE to_entity = ?2",
                libsql::params![canonical_id, alias_id],
            )
            .await
            .map_err(|e| WenlanError::VectorDb(format!("merge_entities rel.to: {e}")))?;

            conn.execute(
                "UPDATE observations SET entity_id = ?1 WHERE entity_id = ?2",
                libsql::params![canonical_id, alias_id],
            )
            .await
            .map_err(|e| WenlanError::VectorDb(format!("merge_entities obs: {e}")))?;

            conn.execute(
                "UPDATE memories SET entity_id = ?1 WHERE entity_id = ?2",
                libsql::params![canonical_id, alias_id],
            )
            .await
            .map_err(|e| WenlanError::VectorDb(format!("merge_entities mem: {e}")))?;

            conn.execute(
                "INSERT OR IGNORE INTO memory_entities (memory_id, entity_id)
                 SELECT memory_id, ?1 FROM memory_entities WHERE entity_id = ?2",
                libsql::params![canonical_id, alias_id],
            )
            .await
            .map_err(|e| WenlanError::VectorDb(format!("merge_entities memory links: {e}")))?;

            conn.execute(
                "DELETE FROM memory_entities WHERE entity_id = ?1",
                libsql::params![alias_id],
            )
            .await
            .map_err(|e| WenlanError::VectorDb(format!("merge_entities old links: {e}")))?;

            conn.execute(
                "UPDATE pages SET entity_id = ?1 WHERE entity_id = ?2",
                libsql::params![canonical_id, alias_id],
            )
            .await
            .map_err(|e| WenlanError::VectorDb(format!("merge_entities pages: {e}")))?;

            conn.execute(
                "UPDATE OR IGNORE entity_aliases SET canonical_entity_id = ?1 WHERE canonical_entity_id = ?2",
                libsql::params![canonical_id, alias_id],
            )
            .await
            .map_err(|e| WenlanError::VectorDb(format!("merge_entities alias redirect: {e}")))?;

            if let Some(name) = &alias_name {
                conn.execute(
                    "INSERT OR IGNORE INTO entity_aliases (alias_name, canonical_entity_id, created_at, source) \
                     VALUES (?1, ?2, unixepoch(), 'merge')",
                    libsql::params![name.as_str(), canonical_id],
                )
                .await
                .map_err(|e| WenlanError::VectorDb(format!("merge_entities alias register: {e}")))?;
            }

            // T16 conservative type-promotion: generic canonical -> alias's
            // concrete type. The WHERE guard re-checks both conditions in SQL so
            // a concurrent write can't demote a concrete canonical. Never flips
            // between two concrete types.
            if should_promote {
                conn.execute(
                    "UPDATE entities SET entity_type = ?1 \
                     WHERE id = ?2 \
                       AND LOWER(entity_type) IN ('entity', 'unknown', '') \
                       AND LOWER(?1) NOT IN ('entity', 'unknown', '')",
                    libsql::params![alias_type.as_str(), canonical_id],
                )
                .await
                .map_err(|e| WenlanError::VectorDb(format!("merge_entities promote type: {e}")))?;
            }

            // T16 band cleanup for the loser (complements ON DELETE CASCADE).
            conn.execute(
                "DELETE FROM entity_minhash_bands WHERE entity_id = ?1",
                libsql::params![alias_id],
            )
            .await
            .map_err(|e| WenlanError::VectorDb(format!("merge_entities band cleanup: {e}")))?;

            conn.execute(
                "DELETE FROM entity_aliases WHERE canonical_entity_id = ?1",
                libsql::params![alias_id],
            )
            .await
            .map_err(|e| WenlanError::VectorDb(format!("merge_entities alias cleanup: {e}")))?;

            conn.execute(
                "DELETE FROM entities WHERE id = ?1",
                libsql::params![alias_id],
            )
            .await
            .map_err(|e| WenlanError::VectorDb(format!("merge_entities delete alias: {e}")))?;

            Ok(())
        }
        .await;

        match result {
            Ok(()) => {
                conn.execute("COMMIT", ())
                    .await
                    .map_err(|e| WenlanError::VectorDb(format!("merge_entities commit: {e}")))?;
                Ok(())
            }
            Err(e) => {
                if let Err(rollback_err) = conn.execute("ROLLBACK", ()).await {
                    log::error!("merge_entities ROLLBACK failed: {rollback_err}");
                }
                Err(e)
            }
        }
    }

    /// Hard-delete the losing relation and return a JSON snapshot of the row
    /// for the caller to record in activity-log payload (soft-archive via log,
    /// not via schema column). `Ok(None)` when loser_id does not exist.
    /// `winner_id` is accepted for activity-log payload at the capability fn
    /// layer; existence not verified here.
    pub async fn supersede_relation(
        &self,
        loser_id: &str,
        winner_id: &str,
    ) -> Result<Option<serde_json::Value>, WenlanError> {
        if loser_id == winner_id {
            return Err(WenlanError::Validation(
                "supersede_relation: loser and winner are the same id".into(),
            ));
        }
        let conn = self.conn.lock().await;

        let mut rows = conn
            .query(
                "SELECT id, from_entity, to_entity, relation_type, source_agent, \
                        confidence, explanation, source_memory_id, created_at \
                 FROM relations WHERE id = ?1",
                libsql::params![loser_id],
            )
            .await
            .map_err(|e| WenlanError::VectorDb(format!("supersede_relation select: {e}")))?;

        let snapshot = rows
            .next()
            .await
            .map_err(|e| WenlanError::VectorDb(format!("supersede_relation row: {e}")))?
            .map(|row| {
                serde_json::json!({
                    "id":               row.get::<String>(0).ok(),
                    "from_entity":      row.get::<String>(1).ok(),
                    "to_entity":        row.get::<String>(2).ok(),
                    "relation_type":    row.get::<String>(3).ok(),
                    "source_agent":     row.get::<String>(4).ok(),
                    "confidence":       row.get::<f64>(5).ok(),
                    "explanation":      row.get::<String>(6).ok(),
                    "source_memory_id": row.get::<String>(7).ok(),
                    "created_at":       row.get::<i64>(8).ok(),
                })
            });
        drop(rows);

        conn.execute(
            "DELETE FROM relations WHERE id = ?1",
            libsql::params![loser_id],
        )
        .await
        .map_err(|e| WenlanError::VectorDb(format!("supersede_relation: {e}")))?;
        Ok(snapshot)
    }

    /// Set `pending_revision = 1` on all chunks matching `source_id`. Idempotent
    /// (re-flag is no-op; the UPDATE matches the same row count). Returns NotFound
    /// when zero rows matched.
    pub async fn flag_memory_for_revision(&self, source_id: &str) -> Result<(), WenlanError> {
        let conn = self.conn.lock().await;
        let rows = conn
            .execute(
                "UPDATE memories SET pending_revision = 1 WHERE source_id = ?1",
                libsql::params![source_id],
            )
            .await
            .map_err(|e| WenlanError::VectorDb(format!("flag_memory_for_revision: {e}")))?;
        if rows == 0 {
            return Err(WenlanError::NotFound(format!(
                "memory {source_id} not found"
            )));
        }
        Ok(())
    }

    /// Create a relation between two entities.
    /// The relation type is normalized against the vocabulary via `resolve_relation_type`
    /// before insertion. On conflict (same from/to/type), updates confidence if higher
    /// and fills in explanation/source_memory_id if previously null.
    /// Returns the ID of the inserted or existing relation.
    #[allow(clippy::too_many_arguments)]
    pub async fn create_relation(
        &self,
        from_entity: &str,
        to_entity: &str,
        relation_type: &str,
        source_agent: Option<&str>,
        confidence: Option<f64>,
        explanation: Option<&str>,
        source_memory_id: Option<&str>,
    ) -> Result<String, WenlanError> {
        // Normalize relation type against vocabulary.
        // NOTE: resolve_relation_type acquires the conn lock, so we must not hold it here.
        let canonical = match self.resolve_relation_type(relation_type).await? {
            Some(c) => c,
            None => {
                log::warn!(
                    "[create_relation] non-vocabulary type '{}' coerced to 'related_to' (caller should use a canonical type)",
                    relation_type
                );
                "related_to".to_string()
            }
        };

        let id = uuid::Uuid::new_v4().to_string();
        let now = chrono::Utc::now().timestamp();

        let conn = self.conn.lock().await;

        // Upsert: insert new or update existing if new confidence is higher.
        let affected = conn.execute(
            "INSERT INTO relations (id, from_entity, to_entity, relation_type, source_agent, confidence, explanation, source_memory_id, created_at)
             VALUES (?1, ?2, ?3, ?4, ?5, ?6, ?7, ?8, ?9)
             ON CONFLICT(from_entity, to_entity, relation_type) DO UPDATE SET
                 confidence = CASE
                     WHEN EXCLUDED.confidence IS NOT NULL AND (confidence IS NULL OR EXCLUDED.confidence > confidence)
                     THEN EXCLUDED.confidence ELSE confidence END,
                 explanation = CASE
                     WHEN EXCLUDED.confidence IS NOT NULL AND (confidence IS NULL OR EXCLUDED.confidence > confidence)
                     THEN COALESCE(EXCLUDED.explanation, explanation) ELSE explanation END,
                 source_memory_id = COALESCE(EXCLUDED.source_memory_id, source_memory_id)",
            libsql::params![
                id.clone(),
                from_entity.to_string(),
                to_entity.to_string(),
                canonical.clone(),
                source_agent.map(|s| libsql::Value::Text(s.to_string())).unwrap_or(libsql::Value::Null),
                confidence.map(libsql::Value::Real).unwrap_or(libsql::Value::Null),
                explanation.map(|s| libsql::Value::Text(s.to_string())).unwrap_or(libsql::Value::Null),
                source_memory_id.map(|s| libsql::Value::Text(s.to_string())).unwrap_or(libsql::Value::Null),
                now
            ],
        )
        .await
        .map_err(|e| WenlanError::VectorDb(format!("create_relation: {}", e)))?;

        // Only increment vocabulary count for genuinely new relations.
        if affected > 0 {
            // Check if this was an insert (the id we generated exists) vs an update.
            let mut rows = conn
                .query(
                    "SELECT id FROM relations WHERE from_entity = ?1 AND to_entity = ?2 AND relation_type = ?3",
                    libsql::params![from_entity.to_string(), to_entity.to_string(), canonical.clone()],
                )
                .await
                .map_err(|e| WenlanError::VectorDb(format!("create_relation check: {}", e)))?;
            let existing_id = match rows.next().await {
                Ok(Some(row)) => row.get::<String>(0).unwrap_or(id.clone()),
                _ => id.clone(),
            };
            drop(rows);
            drop(conn);

            // Only count new inserts (our generated id matches the stored id).
            if existing_id == id {
                self.increment_relation_type_count(&canonical).await.ok();
            }

            return Ok(existing_id);
        }

        drop(conn);
        Ok(id)
    }

    pub async fn list_relations_between(
        &self,
        from_entity: &str,
        to_entity: &str,
    ) -> Result<Vec<(String, String)>, WenlanError> {
        let conn = self.conn.lock().await;
        let mut rows = conn
            .query(
                "SELECT id, relation_type FROM relations WHERE from_entity = ?1 AND to_entity = ?2",
                libsql::params![from_entity.to_string(), to_entity.to_string()],
            )
            .await
            .map_err(|e| WenlanError::VectorDb(e.to_string()))?;
        let mut result = Vec::new();
        while let Some(row) = rows
            .next()
            .await
            .map_err(|e| WenlanError::VectorDb(e.to_string()))?
        {
            result.push((
                row.get::<String>(0).unwrap_or_default(),
                row.get::<String>(1).unwrap_or_default(),
            ));
        }
        Ok(result)
    }

    pub async fn entity_exists(&self, entity_id: &str) -> Result<bool, WenlanError> {
        let conn = self.conn.lock().await;
        let mut rows = conn
            .query(
                "SELECT 1 FROM entities WHERE id = ?1 LIMIT 1",
                libsql::params![entity_id],
            )
            .await
            .map_err(|e| WenlanError::VectorDb(e.to_string()))?;
        Ok(rows
            .next()
            .await
            .map_err(|e| WenlanError::VectorDb(e.to_string()))?
            .is_some())
    }

    pub async fn list_entities(
        &self,
        entity_type: Option<&str>,
        space: Option<&str>,
    ) -> Result<Vec<Entity>, WenlanError> {
        let conn = self.conn.lock().await;

        let mut sql = String::from(
            "SELECT id, name, entity_type, space, source_agent, confidence, confirmed, created_at, updated_at
             FROM entities WHERE 1=1"
        );
        let mut params: Vec<libsql::Value> = Vec::new();

        if let Some(et) = entity_type {
            params.push(et.into());
            sql.push_str(&format!(" AND entity_type = ?{}", params.len()));
        }
        if let Some(d) = space {
            if d == "uncategorized" {
                sql.push_str(" AND space IS NULL");
            } else {
                params.push(d.into());
                sql.push_str(&format!(" AND space = ?{}", params.len()));
            }
        }

        sql.push_str(" ORDER BY updated_at DESC");

        let mut rows = conn
            .query(&sql, libsql::params_from_iter(params))
            .await
            .map_err(|e| WenlanError::VectorDb(format!("list_entities: {}", e)))?;

        let mut entities = Vec::new();
        while let Some(row) = rows
            .next()
            .await
            .map_err(|e| WenlanError::VectorDb(e.to_string()))?
        {
            entities.push(Entity {
                id: row.get::<String>(0).unwrap_or_default(),
                name: row.get::<String>(1).unwrap_or_default(),
                entity_type: row.get::<String>(2).unwrap_or_default(),
                space: row.get::<Option<String>>(3).unwrap_or(None),
                source_agent: row.get::<Option<String>>(4).unwrap_or(None),
                confidence: row.get::<Option<f64>>(5).unwrap_or(None).map(|v| v as f32),
                confirmed: row.get::<i64>(6).unwrap_or(0) != 0,
                created_at: row.get::<i64>(7).unwrap_or(0),
                updated_at: row.get::<i64>(8).unwrap_or(0),
            });
        }
        Ok(entities)
    }

    pub async fn get_entity_detail(&self, entity_id: &str) -> Result<EntityDetail, WenlanError> {
        let conn = self.conn.lock().await;

        // Fetch entity
        let mut rows = conn
            .query(
                "SELECT id, name, entity_type, space, source_agent, confidence, confirmed, created_at, updated_at
                 FROM entities WHERE id = ?1",
                libsql::params![entity_id],
            )
            .await
            .map_err(|e| WenlanError::VectorDb(format!("get_entity: {}", e)))?;

        let entity = if let Some(row) = rows
            .next()
            .await
            .map_err(|e| WenlanError::VectorDb(e.to_string()))?
        {
            Entity {
                id: row.get::<String>(0).unwrap_or_default(),
                name: row.get::<String>(1).unwrap_or_default(),
                entity_type: row.get::<String>(2).unwrap_or_default(),
                space: row.get::<Option<String>>(3).unwrap_or(None),
                source_agent: row.get::<Option<String>>(4).unwrap_or(None),
                confidence: row.get::<Option<f64>>(5).unwrap_or(None).map(|v| v as f32),
                confirmed: row.get::<i64>(6).unwrap_or(0) != 0,
                created_at: row.get::<i64>(7).unwrap_or(0),
                updated_at: row.get::<i64>(8).unwrap_or(0),
            }
        } else {
            return Err(WenlanError::VectorDb(format!(
                "Entity not found: {}",
                entity_id
            )));
        };

        // Fetch observations
        let mut obs_rows = conn
            .query(
                "SELECT id, entity_id, content, source_agent, confidence, confirmed, created_at
                 FROM observations WHERE entity_id = ?1 ORDER BY created_at DESC",
                libsql::params![entity_id],
            )
            .await
            .map_err(|e| WenlanError::VectorDb(format!("get_observations: {}", e)))?;

        let mut observations = Vec::new();
        while let Some(row) = obs_rows
            .next()
            .await
            .map_err(|e| WenlanError::VectorDb(e.to_string()))?
        {
            observations.push(Observation {
                id: row.get::<String>(0).unwrap_or_default(),
                entity_id: row.get::<String>(1).unwrap_or_default(),
                content: row.get::<String>(2).unwrap_or_default(),
                source_agent: row.get::<Option<String>>(3).unwrap_or(None),
                confidence: row.get::<Option<f64>>(4).unwrap_or(None).map(|v| v as f32),
                confirmed: row.get::<i64>(5).unwrap_or(0) != 0,
                created_at: row.get::<i64>(6).unwrap_or(0),
            });
        }

        // Fetch relations (both directions) with entity names
        let mut rel_rows = conn
            .query(
                "SELECT r.id, r.relation_type, r.source_agent, r.created_at,
                        'outgoing' as direction, r.to_entity as entity_id,
                        e.name as entity_name, e.entity_type as entity_type
                 FROM relations r JOIN entities e ON e.id = r.to_entity
                 WHERE r.from_entity = ?1
                 UNION ALL
                 SELECT r.id, r.relation_type, r.source_agent, r.created_at,
                        'incoming' as direction, r.from_entity as entity_id,
                        e.name as entity_name, e.entity_type as entity_type
                 FROM relations r JOIN entities e ON e.id = r.from_entity
                 WHERE r.to_entity = ?1
                 ORDER BY 4 DESC",
                libsql::params![entity_id],
            )
            .await
            .map_err(|e| WenlanError::VectorDb(format!("get_relations: {}", e)))?;

        let mut relations = Vec::new();
        while let Some(row) = rel_rows
            .next()
            .await
            .map_err(|e| WenlanError::VectorDb(e.to_string()))?
        {
            relations.push(RelationWithEntity {
                id: row.get::<String>(0).unwrap_or_default(),
                relation_type: row.get::<String>(1).unwrap_or_default(),
                source_agent: row.get::<Option<String>>(2).unwrap_or(None),
                created_at: row.get::<i64>(3).unwrap_or(0),
                direction: row.get::<String>(4).unwrap_or_default(),
                entity_id: row.get::<String>(5).unwrap_or_default(),
                entity_name: row.get::<String>(6).unwrap_or_default(),
                entity_type: row.get::<String>(7).unwrap_or_default(),
            });
        }

        Ok(EntityDetail {
            entity,
            observations,
            relations,
        })
    }

