    pub async fn set_stability(&self, source_id: &str, stability: &str) -> Result<(), WenlanError> {
        if !matches!(stability, "new" | "learned" | "confirmed") {
            return Err(WenlanError::VectorDb(format!(
                "invalid stability: {}",
                stability
            )));
        }
        let conn = self.conn.lock().await;
        let confirmed_int: i64 = if stability == "confirmed" { 1 } else { 0 };
        if stability == "confirmed" {
            conn.execute(
                "UPDATE memories SET stability = ?1, confirmed = ?2, confidence = 1.0 WHERE source_id = ?3 AND source = 'memory'",
                libsql::params![stability.to_string(), confirmed_int, source_id.to_string()],
            ).await.map_err(|e| WenlanError::VectorDb(format!("set_stability: {}", e)))?;
        } else {
            conn.execute(
                "UPDATE memories SET stability = ?1, confirmed = ?2 WHERE source_id = ?3 AND source = 'memory'",
                libsql::params![stability.to_string(), confirmed_int, source_id.to_string()],
            ).await.map_err(|e| WenlanError::VectorDb(format!("set_stability: {}", e)))?;
        }
        Ok(())
    }

    pub async fn confirm_memory(&self, source_id: &str) -> Result<(), WenlanError> {
        self.set_stability(source_id, "confirmed").await
    }

    /// Returns up to `limit` memories that need human review, ranked by priority:
    /// 1. Low quality from untrusted agents
    /// 2. Low confidence
    /// 3. Oldest unreviewed new memories
    pub async fn get_nurture_cards(
        &self,
        limit: usize,
        domain_filter: Option<&str>,
    ) -> Result<Vec<MemoryItem>, WenlanError> {
        let conn = self.conn.lock().await;
        let space_clause = match domain_filter {
            Some("uncategorized") => "AND c.space IS NULL",
            Some(_) => "AND c.space = ?2",
            None => "",
        };
        let sql = format!(
            "SELECT c.source_id, c.title, c.content, c.summary, c.memory_type, c.space,
                    c.source_agent, c.confidence, c.confirmed, c.stability,
                    c.pinned, c.supersedes, c.last_modified,
                    c.entity_id, c.quality, COALESCE(c.is_recap, 0) as is_recap,
                    (SELECT CASE
                        WHEN COUNT(es.source_id) = 0 THEN 'raw'
                        WHEN SUM(CASE WHEN es.status = 'failed' OR es.status = 'abandoned' THEN 1 ELSE 0 END) = 0 THEN 'enriched'
                        WHEN SUM(CASE WHEN es.status IN ('ok','skipped') THEN 1 ELSE 0 END) = 0 THEN 'enrichment_failed'
                        ELSE 'enrichment_partial'
                    END FROM enrichment_steps es WHERE es.source_id = c.source_id) AS enrichment_status, c.supersede_mode, c.structured_fields,
                    c.retrieval_cue, c.access_count, c.source_text,
                    c.version, c.changelog
             FROM memories c
             WHERE c.source = 'memory'
               AND c.stability = 'new'
               AND COALESCE(c.is_recap, 0) = 0
               AND c.source_id NOT IN (
                   SELECT supersedes FROM memories WHERE supersedes IS NOT NULL AND source = 'memory'
               )
               {}
             ORDER BY
               c.pending_revision DESC,
               CASE c.quality WHEN 'low' THEN 0 WHEN 'medium' THEN 1 ELSE 2 END ASC,
               c.confidence ASC,
               c.last_modified DESC
             LIMIT ?1",
            space_clause
        );

        let mut rows = match domain_filter {
            Some("uncategorized") | None => conn.query(&sql, libsql::params![limit as i64]).await,
            Some(space) => {
                conn.query(&sql, libsql::params![limit as i64, space.to_string()])
                    .await
            }
        }
        .map_err(|e| WenlanError::VectorDb(format!("get_nurture_cards: {}", e)))?;

        let mut results = Vec::new();
        while let Some(row) = rows
            .next()
            .await
            .map_err(|e| WenlanError::VectorDb(e.to_string()))?
        {
            // Column order: 0=source_id, 1=title, 2=content, 3=summary, 4=memory_type,
            // 5=space, 6=source_agent, 7=confidence, 8=confirmed, 9=stability, 10=pinned,
            // 11=supersedes, 12=last_modified, 13=entity_id, 14=quality, 15=is_recap,
            // 16=enrichment_status, 17=supersede_mode, 18=structured_fields, 19=retrieval_cue,
            // 20=access_count, 21=source_text
            results.push(MemoryItem {
                source_id: row.get::<String>(0).unwrap_or_default(),
                title: row.get::<String>(1).unwrap_or_default(),
                content: row.get::<String>(2).unwrap_or_default(),
                summary: row.get::<Option<String>>(3).unwrap_or(None),
                memory_type: row.get::<Option<String>>(4).unwrap_or(None),
                space: row.get::<Option<String>>(5).unwrap_or(None),
                source_agent: row.get::<Option<String>>(6).unwrap_or(None),
                confidence: row.get::<Option<f64>>(7).unwrap_or(None).map(|v| v as f32),
                confirmed: row.get::<i64>(8).unwrap_or(0) != 0,
                stability: row.get::<Option<String>>(9).unwrap_or(None),
                pinned: row.get::<i64>(10).unwrap_or(0) != 0,
                supersedes: row.get::<Option<String>>(11).unwrap_or(None),
                last_modified: row.get::<i64>(12).unwrap_or(0),
                chunk_count: 1,
                entity_id: row.get::<Option<String>>(13).unwrap_or(None),
                quality: row.get::<Option<String>>(14).unwrap_or(None),
                is_recap: row.get::<i64>(15).unwrap_or(0) != 0,
                enrichment_status: row.get::<String>(16).unwrap_or_else(|_| "raw".to_string()),
                supersede_mode: row.get::<String>(17).unwrap_or_else(|_| "hide".to_string()),
                structured_fields: row.get::<Option<String>>(18).unwrap_or(None),
                retrieval_cue: row.get::<Option<String>>(19).unwrap_or(None),
                access_count: row.get::<u64>(20).unwrap_or(0),
                source_text: row.get::<Option<String>>(21).unwrap_or(None),
                version: row.get::<i64>(22).unwrap_or(1),
                changelog: row.get::<Option<String>>(23).unwrap_or(None),
                pending_revision: false,
                merged_from: None,
            });
        }
        Ok(results)
    }

    /// Promote 'new' memories to 'learned' if they've survived min_age_days without contradiction.
    /// Protected tier (identity, preference) never auto-promotes.
    pub async fn promote_uncontradicted(&self, min_age_days: i64) -> Result<usize, WenlanError> {
        let conn = self.conn.lock().await;
        let cutoff = chrono::Utc::now().timestamp() - (min_age_days * 86400);
        // TODO: Add contradiction check — exclude memories flagged in refinement_queue
        // Currently promotes all qualifying memories regardless of contradiction status.
        // When refinement_queue.action = 'detect_contradiction' is reliably populated,
        // add: AND source_id NOT IN (SELECT target_id FROM refinement_queue WHERE action = 'detect_contradiction' AND status = 'pending')
        let changed = conn
            .execute(
                "UPDATE memories SET stability = 'learned', confirmed = 0
             WHERE source = 'memory'
               AND stability = 'new'
               AND memory_type NOT IN ('identity', 'preference')
               AND COALESCE(quality, 'medium') != 'low'
               AND last_modified < ?1",
                libsql::params![cutoff],
            )
            .await
            .map_err(|e| WenlanError::VectorDb(format!("promote_uncontradicted: {}", e)))?;
        Ok(changed as usize)
    }

    /// Resolve an accept/dismiss `id` to `(revision_source_id, target_source_id)`.
    ///
    /// `id` may be the revision's own `source_id` (exact: what the curate cards
    /// key on, so the named revision is acted on even when several compete for
    /// one target) or the target memory's `source_id` (legacy callers: the
    /// NEWEST pending revision superseding it, deterministic by `last_modified`).
    /// A revision's id never equals its target's, so the revision-first lookup is
    /// unambiguous. Returns `None` if neither matches a pending revision.
    async fn resolve_pending_revision(
        conn: &libsql::Connection,
        id: &str,
    ) -> Result<Option<(String, String)>, WenlanError> {
        // 1. `id` is the revision's own source_id (exact).
        let mut rows = conn
            .query(
                "SELECT source_id, supersedes FROM memories \
                 WHERE source_id = ?1 AND pending_revision = 1 AND supersedes IS NOT NULL AND source = 'memory' LIMIT 1",
                libsql::params![id.to_string()],
            )
            .await
            .map_err(|e| WenlanError::VectorDb(format!("resolve_pending_revision rev: {e}")))?;
        if let Some(row) = rows
            .next()
            .await
            .map_err(|e| WenlanError::VectorDb(e.to_string()))?
        {
            let rev = row
                .get::<String>(0)
                .map_err(|e| WenlanError::VectorDb(e.to_string()))?;
            let target = row
                .get::<String>(1)
                .map_err(|e| WenlanError::VectorDb(e.to_string()))?;
            return Ok(Some((rev, target)));
        }

        // 2. `id` is the target (legacy): newest pending revision superseding it.
        let mut rows = conn
            .query(
                "SELECT source_id, supersedes FROM memories \
                 WHERE supersedes = ?1 AND pending_revision = 1 AND source = 'memory' \
                 ORDER BY last_modified DESC LIMIT 1",
                libsql::params![id.to_string()],
            )
            .await
            .map_err(|e| WenlanError::VectorDb(format!("resolve_pending_revision target: {e}")))?;
        if let Some(row) = rows
            .next()
            .await
            .map_err(|e| WenlanError::VectorDb(e.to_string()))?
        {
            let rev = row
                .get::<String>(0)
                .map_err(|e| WenlanError::VectorDb(e.to_string()))?;
            let target = row
                .get::<String>(1)
                .map_err(|e| WenlanError::VectorDb(e.to_string()))?;
            return Ok(Some((rev, target)));
        }

        Ok(None)
    }

    /// Accept a pending revision identified by `id` (the revision's own
    /// `source_id`, or legacy target source_id). Activates exactly that revision
    /// (all its chunk rows) and suppresses its target. Sibling revisions are left
    /// pending. Returns `(target_source_id, revision_source_id)`.
    pub async fn accept_pending_revision(&self, id: &str) -> Result<(String, String), WenlanError> {
        let conn = self.conn.lock().await;
        let (revision_source_id, target_source_id) = Self::resolve_pending_revision(&conn, id)
            .await?
            .ok_or_else(|| {
                WenlanError::NotFound(format!("No pending revision for source_id: {id}"))
            })?;

        conn.execute("BEGIN", ())
            .await
            .map_err(|e| WenlanError::VectorDb(format!("accept_pending_revision begin: {}", e)))?;

        let activate_result = conn
            .execute(
                "UPDATE memories SET pending_revision = 0, confirmed = 1, stability = 'confirmed', confidence = 1.0 WHERE source_id = ?1",
                libsql::params![revision_source_id.clone()],
            )
            .await;
        if let Err(e) = activate_result {
            let _ = conn.execute("ROLLBACK", ()).await;
            return Err(WenlanError::VectorDb(format!(
                "accept_pending_revision activate: {}",
                e
            )));
        }

        let suppress_result = conn
            .execute(
                "UPDATE memories SET confirmed = 0, stability = 'new' WHERE source_id = ?1",
                libsql::params![target_source_id.clone()],
            )
            .await;
        if let Err(e) = suppress_result {
            let _ = conn.execute("ROLLBACK", ()).await;
            return Err(WenlanError::VectorDb(format!(
                "accept_pending_revision suppress: {}",
                e
            )));
        }

        conn.execute("COMMIT", ())
            .await
            .map_err(|e| WenlanError::VectorDb(format!("accept_pending_revision commit: {}", e)))?;

        Ok((target_source_id, revision_source_id))
    }

    /// Dismiss a pending revision identified by `id` (the revision's own
    /// `source_id`, or legacy target source_id). Unstages exactly that one
    /// revision: clears its `pending_revision` + `supersedes` so it survives
    /// as an independent memory (not deleted); sibling revisions and the
    /// original are untouched. Returns `(target_source_id, revision_source_id)`.
    pub async fn dismiss_pending_revision(
        &self,
        id: &str,
    ) -> Result<(String, String), WenlanError> {
        let conn = self.conn.lock().await;
        let (revision_source_id, target_source_id) = Self::resolve_pending_revision(&conn, id)
            .await?
            .ok_or_else(|| {
                WenlanError::NotFound(format!("No pending revision for source_id: {id}"))
            })?;
        // Unstage, not delete: "dismiss" means "this is NOT a revision of the
        // target", so drop the false revision link (clear pending_revision +
        // supersedes) and keep the memory as an independent row. Deleting it
        // would destroy a distinct captured memory whenever the staging was a
        // false positive (the topic-match treadmill). A genuinely unwanted
        // capture is removed separately via `forget`.
        conn.execute(
            "UPDATE memories SET pending_revision = 0, supersedes = NULL WHERE source_id = ?1",
            libsql::params![revision_source_id.clone()],
        )
        .await
        .map_err(|e| WenlanError::VectorDb(format!("dismiss_pending_revision: {}", e)))?;
        Ok((target_source_id, revision_source_id))
    }

    pub async fn get_pending_revision_for(
        &self,
        target_source_id: &str,
    ) -> Result<Option<PendingRevision>, WenlanError> {
        let conn = self.conn.lock().await;
        let mut rows = conn
            .query(
                "SELECT source_id, content, source_agent FROM memories WHERE supersedes = ?1 AND pending_revision = 1 AND source = 'memory' LIMIT 1",
                libsql::params![target_source_id.to_string()],
            )
            .await
            .map_err(|e| WenlanError::VectorDb(format!("get_pending_revision_for: {}", e)))?;
        if let Some(row) = rows
            .next()
            .await
            .map_err(|e| WenlanError::VectorDb(e.to_string()))?
        {
            Ok(Some(PendingRevision {
                source_id: row
                    .get::<String>(0)
                    .map_err(|e| WenlanError::VectorDb(e.to_string()))?,
                content: row
                    .get::<String>(1)
                    .map_err(|e| WenlanError::VectorDb(e.to_string()))?,
                source_agent: row.get::<Option<String>>(2).unwrap_or(None),
            }))
        } else {
            Ok(None)
        }
    }

    /// List staged revisions awaiting human accept/dismiss.
    ///
    /// Returns `(target_source_id, revision_source_id, revision_content,
    /// source_agent, last_modified)` for every row where
    /// `pending_revision = 1` AND `supersedes IS NOT NULL` AND
    /// `source = 'memory'`. Sorted newest-first by `last_modified`
    /// (the only `NOT NULL` timestamp on memories; `created_at` is
    /// nullable pre-migration-21).
    ///
    /// The partial index `idx_memories_pending_revision` covers the
    /// primary `pending_revision != 0` filter; the residual `source` and
    /// `supersedes IS NOT NULL` scan is bounded by human-attention
    /// cardinality.
    pub async fn list_pending_revisions(
        &self,
        limit: usize,
    ) -> Result<Vec<wenlan_types::responses::PendingRevisionItem>, WenlanError> {
        let conn = self.conn.lock().await;
        let mut rows = conn
            .query(
                "SELECT supersedes, source_id, content, source_agent, last_modified, structured_fields \
                 FROM memories \
                 WHERE pending_revision = 1 \
                   AND supersedes IS NOT NULL \
                   AND source = 'memory' \
                 ORDER BY last_modified DESC \
                 LIMIT ?1",
                libsql::params![limit as i64],
            )
            .await
            .map_err(|e| WenlanError::VectorDb(format!("list_pending_revisions: {e}")))?;

        let mut out = Vec::new();
        while let Some(row) = rows
            .next()
            .await
            .map_err(|e| WenlanError::VectorDb(format!("list_pending_revisions row: {e}")))?
        {
            let grounded_in = row
                .get::<Option<String>>(5)
                .unwrap_or(None)
                .and_then(|sf| serde_json::from_str::<serde_json::Value>(&sf).ok())
                .and_then(|v| {
                    v.get("grounded_in")
                        .and_then(|g| g.as_str())
                        .map(str::to_string)
                });
            out.push(wenlan_types::responses::PendingRevisionItem {
                target_source_id: row
                    .get::<String>(0)
                    .map_err(|e| WenlanError::VectorDb(format!("col 0: {e}")))?,
                revision_source_id: row
                    .get::<String>(1)
                    .map_err(|e| WenlanError::VectorDb(format!("col 1: {e}")))?,
                revision_content: row
                    .get::<String>(2)
                    .map_err(|e| WenlanError::VectorDb(format!("col 2: {e}")))?,
                source_agent: row.get::<Option<String>>(3).unwrap_or(None),
                last_modified: row
                    .get::<i64>(4)
                    .map_err(|e| WenlanError::VectorDb(format!("col 4: {e}")))?,
                grounded_in,
            });
        }
        Ok(out)
    }

    // ---- doc-reconcile sweep (doc-grounded revisions, L3) ----

    /// Doc chunks new or re-ingested since the (ts, id, chunk) cursor, ascending.
    pub async fn reconcile_doc_frontier(
        &self,
        after_ts: i64,
        after_id: &str,
        after_chunk: i64,
        limit: usize,
    ) -> Result<Vec<crate::reconcile::ReconcileItem>, WenlanError> {
        let sql = "SELECT source_id, chunk_index, content, space, last_modified, content_hash \
                   FROM memories \
                   WHERE source_agent = 'folder' \
                     AND (last_modified > ?1 OR (last_modified = ?1 AND \
                          (source_id > ?2 OR (source_id = ?2 AND chunk_index > ?3)))) \
                   ORDER BY last_modified ASC, source_id ASC, chunk_index ASC \
                   LIMIT ?4";
        self.reconcile_frontier_rows(sql, after_ts, after_id, after_chunk, limit)
            .await
    }

    /// Live confirmed captures created/modified since the cursor, ascending.
    /// Excludes 'folder' (docs), 'reconcile' (accepted revisions — no self-churn),
    /// unconfirmed rows, and rows already staged as pending revisions.
    pub async fn reconcile_capture_frontier(
        &self,
        after_ts: i64,
        after_id: &str,
        after_chunk: i64,
        limit: usize,
    ) -> Result<Vec<crate::reconcile::ReconcileItem>, WenlanError> {
        let sql = "SELECT source_id, chunk_index, content, space, last_modified, content_hash \
                   FROM memories \
                   WHERE source = 'memory' AND chunk_index = 0 AND confirmed = 1 \
                     AND pending_revision = 0 \
                     AND (source_agent IS NULL OR source_agent NOT IN ('folder', 'reconcile')) \
                     AND (last_modified > ?1 OR (last_modified = ?1 AND \
                          (source_id > ?2 OR (source_id = ?2 AND chunk_index > ?3)))) \
                   ORDER BY last_modified ASC, source_id ASC, chunk_index ASC \
                   LIMIT ?4";
        self.reconcile_frontier_rows(sql, after_ts, after_id, after_chunk, limit)
            .await
    }

    async fn reconcile_frontier_rows(
        &self,
        sql: &str,
        after_ts: i64,
        after_id: &str,
        after_chunk: i64,
        limit: usize,
    ) -> Result<Vec<crate::reconcile::ReconcileItem>, WenlanError> {
        let conn = self.conn.lock().await;
        let mut rows = conn
            .query(
                sql,
                libsql::params![after_ts, after_id, after_chunk, limit as i64],
            )
            .await
            .map_err(|e| WenlanError::VectorDb(format!("reconcile_frontier: {e}")))?;
        let mut out = Vec::new();
        while let Some(row) = rows
            .next()
            .await
            .map_err(|e| WenlanError::VectorDb(format!("reconcile_frontier row: {e}")))?
        {
            out.push(crate::reconcile::ReconcileItem {
                source_id: row.get::<String>(0).unwrap_or_default(),
                chunk_index: row.get::<i64>(1).unwrap_or(0),
                content: row.get::<String>(2).unwrap_or_default(),
                space: row.get::<Option<String>>(3).unwrap_or(None),
                last_modified: row.get::<i64>(4).unwrap_or(0),
                content_hash: row.get::<Option<String>>(5).unwrap_or(None),
            });
        }
        Ok(out)
    }

    /// True when a revision row already carries this (revises, grounded_in, doc_hash)
    /// triple — the file-level treadmill guard. Quoted-LIKE avoids the
    /// LIKE-against-JSON substring class (mem_1 vs mem_10).
    pub async fn reconcile_pair_exists(
        &self,
        revises: &str,
        grounded_in: &str,
        doc_hash: &str,
    ) -> Result<bool, WenlanError> {
        let p_rev = format!("%\"revises\":\"{revises}\"%");
        let p_gnd = format!("%\"grounded_in\":\"{grounded_in}\"%");
        let p_hash = format!("%\"doc_hash\":\"{doc_hash}\"%");
        let conn = self.conn.lock().await;
        let mut rows = conn
            .query(
                "SELECT 1 FROM memories WHERE source_agent = 'reconcile' \
                 AND structured_fields LIKE ?1 AND structured_fields LIKE ?2 \
                 AND structured_fields LIKE ?3 LIMIT 1",
                libsql::params![p_rev, p_gnd, p_hash],
            )
            .await
            .map_err(|e| WenlanError::VectorDb(format!("reconcile_pair_exists: {e}")))?;
        Ok(rows
            .next()
            .await
            .map_err(|e| WenlanError::VectorDb(format!("reconcile_pair_exists row: {e}")))?
            .is_some())
    }

    /// True when the capture already has ANY pending revision staged against it.
    pub async fn capture_has_pending_revision(
        &self,
        capture_id: &str,
    ) -> Result<bool, WenlanError> {
        let conn = self.conn.lock().await;
        let mut rows = conn
            .query(
                "SELECT 1 FROM memories WHERE pending_revision = 1 AND supersedes = ?1 LIMIT 1",
                libsql::params![capture_id],
            )
            .await
            .map_err(|e| WenlanError::VectorDb(format!("capture_has_pending_revision: {e}")))?;
        Ok(rows
            .next()
            .await
            .map_err(|e| WenlanError::VectorDb(format!("capture_has_pending_revision row: {e}")))?
            .is_some())
    }

    /// True when MORE THAN `cap` doc-grounded revisions await human review.
    /// Enumerates up to cap+1 rows instead of COUNT(*) (libsql COUNT-with-vector-index hazard).
    pub async fn pending_reconcile_at_cap(&self, cap: usize) -> Result<bool, WenlanError> {
        let conn = self.conn.lock().await;
        let mut rows = conn
            .query(
                "SELECT 1 FROM memories WHERE source_agent = 'reconcile' \
                 AND pending_revision = 1 LIMIT ?1",
                libsql::params![(cap + 1) as i64],
            )
            .await
            .map_err(|e| WenlanError::VectorDb(format!("pending_reconcile_at_cap: {e}")))?;
        let mut n = 0usize;
        while rows
            .next()
            .await
            .map_err(|e| WenlanError::VectorDb(format!("pending_reconcile_at_cap row: {e}")))?
            .is_some()
        {
            n += 1;
        }
        Ok(n > cap)
    }

    /// Vector top-k candidates on the opposite side of a frontier item, same space
    /// (NULL matches only NULL), cosine similarity >= min_cosine.
    /// toward_docs=true: candidates are doc chunks; false: live captures.
    pub async fn reconcile_candidates(
        &self,
        item_source_id: &str,
        item_chunk_index: i64,
        space: Option<&str>,
        toward_docs: bool,
        k: usize,
        min_cosine: f64,
    ) -> Result<Vec<crate::reconcile::ReconcileCandidate>, WenlanError> {
        // 1. Fetch the frontier item's stored embedding.
        let embedding: Vec<f32> =
            {
                let conn = self.conn.lock().await;
                let mut rows = conn
                    .query(
                        "SELECT embedding FROM memories WHERE source_id = ?1 AND chunk_index = ?2",
                        libsql::params![item_source_id, item_chunk_index],
                    )
                    .await
                    .map_err(|e| WenlanError::VectorDb(format!("reconcile_candidates emb: {e}")))?;
                match rows.next().await.map_err(|e| {
                    WenlanError::VectorDb(format!("reconcile_candidates emb row: {e}"))
                })? {
                    Some(row) => row
                        .get::<Vec<u8>>(0)
                        .unwrap_or_default()
                        .chunks_exact(4)
                        .map(|b| f32::from_le_bytes([b[0], b[1], b[2], b[3]]))
                        .collect(),
                    None => return Ok(Vec::new()),
                }
            };
        if embedding.is_empty() {
            return Ok(Vec::new());
        }
        let vec_str = Self::vec_to_sql(&embedding);

        // 2. ANN probe with over-fetch; predicates cut after the probe.
        // Deliberate asymmetry vs reconcile_capture_frontier: accepted
        // revision rows (source_agent='reconcile') are excluded as frontier
        // FOCUS items (no self-churn) but admitted here as CANDIDATE captures,
        // so a doc that changes later can still propose a revision to an
        // already-accepted revision. reconcile_pair_exists keys on doc_hash,
        // so the unchanged doc can never re-propose (no treadmill).
        let side_predicate = if toward_docs {
            "c.source_agent = 'folder'"
        } else {
            "c.source = 'memory' AND c.chunk_index = 0 AND c.confirmed = 1 \
             AND c.pending_revision = 0 \
             AND (c.source_agent IS NULL OR c.source_agent != 'folder')"
        };
        let sql = format!(
            "SELECT c.source_id, c.chunk_index, c.content, c.last_modified, c.created_at, \
                    c.content_hash, c.source_agent, \
                    vector_distance_cos(c.embedding, vector32(?1)) AS dist \
             FROM vector_top_k('memories_vec_idx', vector32(?1), ?2) AS vt \
             JOIN memories c ON c.rowid = vt.id \
             WHERE {side_predicate} \
               AND ((?3 IS NULL AND c.space IS NULL) OR c.space = ?3) \
               AND c.source_id != ?4 \
             ORDER BY dist ASC"
        );
        let overfetch = (k * 20).max(100) as i64;
        let space_val: libsql::Value = match space {
            Some(s) => s.into(),
            None => libsql::Value::Null,
        };
        let conn = self.conn.lock().await;
        let mut rows = conn
            .query(
                &sql,
                libsql::params![vec_str, overfetch, space_val, item_source_id],
            )
            .await
            .map_err(|e| WenlanError::VectorDb(format!("reconcile_candidates: {e}")))?;
        let mut out = Vec::new();
        while let Some(row) = rows
            .next()
            .await
            .map_err(|e| WenlanError::VectorDb(format!("reconcile_candidates row: {e}")))?
        {
            let dist = row.get::<f64>(7).unwrap_or(1.0);
            let cosine = 1.0 - dist;
            if cosine < min_cosine {
                continue;
            }
            out.push(crate::reconcile::ReconcileCandidate {
                source_id: row.get::<String>(0).unwrap_or_default(),
                chunk_index: row.get::<i64>(1).unwrap_or(0),
                content: row.get::<String>(2).unwrap_or_default(),
                last_modified: row.get::<i64>(3).unwrap_or(0),
                created_at: row.get::<Option<i64>>(4).unwrap_or(None).unwrap_or(0),
                content_hash: row.get::<Option<String>>(5).unwrap_or(None),
                source_agent: row.get::<Option<String>>(6).unwrap_or(None),
                cosine,
            });
            if out.len() >= k {
                break;
            }
        }
        Ok(out)
    }

    // ==================== Session / Activity Methods ====================

    /// Insert or update an activity record.
    pub async fn upsert_activity(
        &self,
        id: &str,
        started_at: i64,
        ended_at: i64,
    ) -> Result<(), WenlanError> {
        let conn = self.conn.lock().await;
        conn.execute(
            "INSERT INTO activities (id, started_at, ended_at) VALUES (?1, ?2, ?3) ON CONFLICT(id) DO UPDATE SET ended_at = ?3",
            libsql::params![id, started_at, ended_at],
        ).await.map_err(|e| WenlanError::VectorDb(format!("upsert_activity: {}", e)))?;
        Ok(())
    }

    /// Get completed activities with ended_at set.
    pub async fn get_completed_activities(
        &self,
        _gap_secs: i64,
    ) -> Result<Vec<ActivityRow>, WenlanError> {
        let conn = self.conn.lock().await;
        let mut rows = conn
            .query(
                "SELECT id, started_at, ended_at FROM activities ORDER BY started_at DESC",
                (),
            )
            .await
            .map_err(|e| WenlanError::VectorDb(format!("get_completed_activities: {}", e)))?;
        let mut results = vec![];
        while let Some(row) = rows
            .next()
            .await
            .map_err(|e| WenlanError::VectorDb(e.to_string()))?
        {
            results.push(ActivityRow {
                id: row
                    .get(0)
                    .map_err(|e| WenlanError::VectorDb(e.to_string()))?,
                started_at: row
                    .get(1)
                    .map_err(|e| WenlanError::VectorDb(e.to_string()))?,
                ended_at: row
                    .get(2)
                    .map_err(|e| WenlanError::VectorDb(e.to_string()))?,
            });
        }
        Ok(results)
    }

    /// Insert a capture reference.
    #[allow(clippy::too_many_arguments)]
    pub async fn insert_capture_ref(
        &self,
        source_id: &str,
        activity_id: &str,
        snapshot_id: Option<&str>,
        app_name: &str,
        window_title: &str,
        timestamp: i64,
        source: &str,
    ) -> Result<(), WenlanError> {
        let conn = self.conn.lock().await;
        conn.execute(
            "INSERT OR REPLACE INTO capture_refs (source_id, activity_id, snapshot_id, app_name, window_title, timestamp, source) VALUES (?1, ?2, ?3, ?4, ?5, ?6, ?7)",
            libsql::params![source_id, activity_id, snapshot_id, app_name, window_title, timestamp, source],
        ).await.map_err(|e| WenlanError::VectorDb(format!("insert_capture_ref: {}", e)))?;
        Ok(())
    }

    /// Get unpackaged captures for a given activity.
    pub async fn get_unpackaged_captures(
        &self,
        activity_id: &str,
    ) -> Result<Vec<CaptureRefRow>, WenlanError> {
        let conn = self.conn.lock().await;
        let mut rows = conn.query(
            "SELECT source_id, activity_id, snapshot_id, app_name, window_title, timestamp, source FROM capture_refs WHERE activity_id = ?1 AND snapshot_id IS NULL ORDER BY timestamp",
            [activity_id],
        ).await.map_err(|e| WenlanError::VectorDb(format!("get_unpackaged_captures: {}", e)))?;
        let mut results = vec![];
        while let Some(row) = rows
            .next()
            .await
            .map_err(|e| WenlanError::VectorDb(e.to_string()))?
        {
            results.push(CaptureRefRow {
                source_id: row
                    .get(0)
                    .map_err(|e| WenlanError::VectorDb(e.to_string()))?,
                activity_id: row
                    .get(1)
                    .map_err(|e| WenlanError::VectorDb(e.to_string()))?,
                snapshot_id: row.get(2).unwrap_or(None),
                app_name: row
                    .get(3)
                    .map_err(|e| WenlanError::VectorDb(e.to_string()))?,
                window_title: row
                    .get(4)
                    .map_err(|e| WenlanError::VectorDb(e.to_string()))?,
                timestamp: row
                    .get(5)
                    .map_err(|e| WenlanError::VectorDb(e.to_string()))?,
                source: row
                    .get(6)
                    .map_err(|e| WenlanError::VectorDb(e.to_string()))?,
            });
        }
        Ok(results)
    }

    /// Mark captures as packaged into a snapshot.
    pub async fn mark_captures_packaged(
        &self,
        source_ids: &[&str],
        snapshot_id: &str,
    ) -> Result<(), WenlanError> {
        let conn = self.conn.lock().await;
        conn.execute("BEGIN", ())
            .await
            .map_err(|e| WenlanError::VectorDb(format!("mark_packaged begin: {}", e)))?;
        for source_id in source_ids {
            conn.execute(
                "UPDATE capture_refs SET snapshot_id = ?1 WHERE source_id = ?2",
                libsql::params![snapshot_id, *source_id],
            )
            .await
            .map_err(|e| WenlanError::VectorDb(format!("mark_packaged update: {}", e)))?;
        }
        conn.execute("COMMIT", ())
            .await
            .map_err(|e| WenlanError::VectorDb(format!("mark_packaged commit: {}", e)))?;
        Ok(())
    }

    /// Check if an activity has any unpackaged captures.
    pub async fn has_unpackaged_captures(&self, activity_id: &str) -> Result<bool, WenlanError> {
        let conn = self.conn.lock().await;
        let mut rows = conn
            .query(
                "SELECT 1 FROM capture_refs WHERE activity_id = ?1 AND snapshot_id IS NULL LIMIT 1",
                [activity_id],
            )
            .await
            .map_err(|e| WenlanError::VectorDb(format!("has_unpackaged: {}", e)))?;
        let has = rows
            .next()
            .await
            .map_err(|e| WenlanError::VectorDb(e.to_string()))?
            .is_some();
        Ok(has)
    }

    /// Get captures belonging to a snapshot.
    pub async fn get_captures_for_snapshot(
        &self,
        snapshot_id: &str,
    ) -> Result<Vec<CaptureRefRow>, WenlanError> {
        let conn = self.conn.lock().await;
        let mut rows = conn.query(
            "SELECT source_id, activity_id, snapshot_id, app_name, window_title, timestamp, source FROM capture_refs WHERE snapshot_id = ?1 ORDER BY timestamp",
            [snapshot_id],
        ).await.map_err(|e| WenlanError::VectorDb(format!("get_captures_for_snapshot: {}", e)))?;
        let mut results = vec![];
        while let Some(row) = rows
            .next()
            .await
            .map_err(|e| WenlanError::VectorDb(e.to_string()))?
        {
            results.push(CaptureRefRow {
                source_id: row
                    .get(0)
                    .map_err(|e| WenlanError::VectorDb(e.to_string()))?,
                activity_id: row
                    .get(1)
                    .map_err(|e| WenlanError::VectorDb(e.to_string()))?,
                snapshot_id: row.get(2).unwrap_or(None),
                app_name: row
                    .get(3)
                    .map_err(|e| WenlanError::VectorDb(e.to_string()))?,
                window_title: row
                    .get(4)
                    .map_err(|e| WenlanError::VectorDb(e.to_string()))?,
                timestamp: row
                    .get(5)
                    .map_err(|e| WenlanError::VectorDb(e.to_string()))?,
                source: row
                    .get(6)
                    .map_err(|e| WenlanError::VectorDb(e.to_string()))?,
            });
        }
        Ok(results)
    }

    // ==================== Session Snapshots ====================

    /// Insert a session snapshot.
    pub async fn insert_snapshot(&self, snap: &SessionSnapshotRow) -> Result<(), WenlanError> {
        let now = chrono::Utc::now().timestamp();
        let apps_json = serde_json::to_string(&snap.primary_apps).unwrap_or_default();
        let tags_json = serde_json::to_string(&snap.tags).unwrap_or_default();
        let conn = self.conn.lock().await;
        conn.execute(
            "INSERT INTO session_snapshots (id, activity_id, started_at, ended_at, primary_apps, summary, tags, capture_count, created_at) VALUES (?1, ?2, ?3, ?4, ?5, ?6, ?7, ?8, ?9)",
            libsql::params![snap.id.clone(), snap.activity_id.clone(), snap.started_at, snap.ended_at, apps_json, snap.summary.clone(), tags_json, snap.capture_count as i64, now],
        ).await.map_err(|e| WenlanError::VectorDb(format!("insert_snapshot: {}", e)))?;
        Ok(())
    }

    /// Get recent session snapshots.
    pub async fn get_recent_snapshots(
        &self,
        limit: usize,
    ) -> Result<Vec<SessionSnapshotRow>, WenlanError> {
        let conn = self.conn.lock().await;
        let mut rows = conn.query(
            "SELECT id, activity_id, started_at, ended_at, primary_apps, summary, tags, capture_count FROM session_snapshots ORDER BY started_at DESC LIMIT ?1",
            [limit as i64],
        ).await.map_err(|e| WenlanError::VectorDb(format!("get_recent_snapshots: {}", e)))?;
        let mut results = vec![];
        while let Some(row) = rows
            .next()
            .await
            .map_err(|e| WenlanError::VectorDb(e.to_string()))?
        {
            let apps_json: String = row
                .get(4)
                .map_err(|e| WenlanError::VectorDb(e.to_string()))?;
            let tags_json: String = row
                .get(6)
                .map_err(|e| WenlanError::VectorDb(e.to_string()))?;
            results.push(SessionSnapshotRow {
                id: row
                    .get(0)
                    .map_err(|e| WenlanError::VectorDb(e.to_string()))?,
                activity_id: row
                    .get(1)
                    .map_err(|e| WenlanError::VectorDb(e.to_string()))?,
                started_at: row
                    .get(2)
                    .map_err(|e| WenlanError::VectorDb(e.to_string()))?,
                ended_at: row
                    .get(3)
                    .map_err(|e| WenlanError::VectorDb(e.to_string()))?,
                primary_apps: serde_json::from_str(&apps_json).unwrap_or_default(),
                summary: row
                    .get(5)
                    .map_err(|e| WenlanError::VectorDb(e.to_string()))?,
                tags: serde_json::from_str(&tags_json).unwrap_or_default(),
                capture_count: row
                    .get::<i64>(7)
                    .map_err(|e| WenlanError::VectorDb(e.to_string()))?
                    as usize,
            });
        }
        Ok(results)
    }

    /// Delete a session snapshot and unlink its captures.
    pub async fn delete_snapshot(&self, snapshot_id: &str) -> Result<(), WenlanError> {
        let conn = self.conn.lock().await;
        conn.execute(
            "UPDATE capture_refs SET snapshot_id = NULL WHERE snapshot_id = ?1",
            [snapshot_id],
        )
        .await
        .map_err(|e| WenlanError::VectorDb(format!("delete_snapshot unlink: {}", e)))?;
        conn.execute("DELETE FROM session_snapshots WHERE id = ?1", [snapshot_id])
            .await
            .map_err(|e| WenlanError::VectorDb(format!("delete_snapshot: {}", e)))?;
        Ok(())
    }

    /// Update a snapshot's summary and tags (called by LLM after synthesis).
    pub async fn update_snapshot_summary(
        &self,
        snapshot_id: &str,
        summary: &str,
        tags: &[String],
    ) -> Result<(), WenlanError> {
        let tags_json = serde_json::to_string(tags).unwrap_or_default();
        let conn = self.conn.lock().await;
        conn.execute(
            "UPDATE session_snapshots SET summary = ?1, tags = ?2 WHERE id = ?3",
            libsql::params![summary, tags_json, snapshot_id],
        )
        .await
        .map_err(|e| WenlanError::VectorDb(format!("update_snapshot_summary: {}", e)))?;
        Ok(())
    }

    /// Delete session data (activities, capture_refs, snapshots) overlapping a time range.
    pub async fn delete_session_by_time_range(
        &self,
        start: i64,
        end: i64,
    ) -> Result<(), WenlanError> {
        let conn = self.conn.lock().await;
        // Find overlapping activity IDs
        let mut rows = conn
            .query(
                "SELECT id FROM activities WHERE started_at <= ?2 AND ended_at >= ?1",
                libsql::params![start, end],
            )
            .await
            .map_err(|e| {
                WenlanError::VectorDb(format!("delete_session_by_time_range query: {}", e))
            })?;
        let mut ids = vec![];
        while let Some(row) = rows
            .next()
            .await
            .map_err(|e| WenlanError::VectorDb(e.to_string()))?
        {
            let id: String = row
                .get(0)
                .map_err(|e| WenlanError::VectorDb(e.to_string()))?;
            ids.push(id);
        }
        drop(rows);

        for id in &ids {
            conn.execute(
                "UPDATE capture_refs SET snapshot_id = NULL WHERE activity_id = ?1 AND snapshot_id IS NOT NULL",
                [id.as_str()],
            ).await.map_err(|e| WenlanError::VectorDb(format!("delete_session unlink: {}", e)))?;
            conn.execute(
                "DELETE FROM session_snapshots WHERE activity_id = ?1",
                [id.as_str()],
            )
            .await
            .map_err(|e| WenlanError::VectorDb(format!("delete_session snapshots: {}", e)))?;
            conn.execute(
                "DELETE FROM capture_refs WHERE activity_id = ?1",
                [id.as_str()],
            )
            .await
            .map_err(|e| WenlanError::VectorDb(format!("delete_session captures: {}", e)))?;
            conn.execute("DELETE FROM activities WHERE id = ?1", [id.as_str()])
                .await
                .map_err(|e| WenlanError::VectorDb(format!("delete_session activity: {}", e)))?;
        }
        Ok(())
    }

