    /// Get briefing stats: dominant domain, primary agent, new-today count.
    pub async fn get_briefing_stats(
        &self,
        cutoff: i64,
    ) -> Result<crate::briefing::BriefingStats, WenlanError> {
        let conn = self.conn.lock().await;
        let today_start = chrono::Utc::now()
            .date_naive()
            .and_hms_opt(0, 0, 0)
            .unwrap()
            .and_utc()
            .timestamp();

        // New memories today
        let mut rows = conn
            .query(
                "SELECT COUNT(DISTINCT source_id) FROM memories \
                 WHERE source = 'memory' AND last_modified > ?1 AND chunk_index = 0",
                libsql::params![today_start],
            )
            .await
            .map_err(|e| WenlanError::VectorDb(format!("briefing_stats new_today: {}", e)))?;
        let new_today = if let Some(row) = rows
            .next()
            .await
            .map_err(|e| WenlanError::VectorDb(e.to_string()))?
        {
            row.get::<u64>(0).unwrap_or(0)
        } else {
            0
        };

        // Dominant space (most frequent in last 48h)
        let mut rows = conn
            .query(
                "SELECT space, COUNT(*) as cnt FROM memories \
                 WHERE source = 'memory' AND last_modified > ?1 AND chunk_index = 0 \
                   AND space IS NOT NULL AND space != '' \
                 GROUP BY space ORDER BY cnt DESC LIMIT 1",
                libsql::params![cutoff],
            )
            .await
            .map_err(|e| WenlanError::VectorDb(format!("briefing_stats domain: {}", e)))?;
        let dominant_domain = if let Some(row) = rows
            .next()
            .await
            .map_err(|e| WenlanError::VectorDb(e.to_string()))?
        {
            row.get::<String>(0).ok()
        } else {
            None
        };

        // Primary agent (most frequent in last 48h)
        let mut rows = conn
            .query(
                "SELECT source_agent, COUNT(*) as cnt FROM memories \
                 WHERE source = 'memory' AND last_modified > ?1 AND chunk_index = 0 \
                   AND source_agent IS NOT NULL AND source_agent != '' \
                 GROUP BY source_agent ORDER BY cnt DESC LIMIT 1",
                libsql::params![cutoff],
            )
            .await
            .map_err(|e| WenlanError::VectorDb(format!("briefing_stats agent: {}", e)))?;
        let primary_agent = if let Some(row) = rows
            .next()
            .await
            .map_err(|e| WenlanError::VectorDb(e.to_string()))?
        {
            row.get::<String>(0).ok()
        } else {
            None
        };

        Ok(crate::briefing::BriefingStats {
            dominant_domain,
            primary_agent,
            new_today,
        })
    }

