    /// L4 CORRUPTION NET: after appending c.importance to the SELECT projections,
    /// a known memory must still round-trip EVERY field. If any row.get(N) offset
    /// shifted, quality/stability/confidence/version/source_text would corrupt.
    #[tokio::test]
    async fn salience_does_not_corrupt_columns() {
        let (db, _dir) = test_db().await;
        let mut doc = make_memory_doc(
            "corrupt_net",
            "Postgres uses MVCC for concurrency control in transactional workloads",
            "fact",
            "databases",
            "claude",
        );
        doc.confidence = Some(0.83);
        doc.stability = Some("learned".to_string());
        doc.quality = Some("high".to_string());
        doc.source_text = Some("ORIGINAL SOURCE TEXT MARKER".to_string());
        db.upsert_documents(vec![doc]).await.unwrap();
        // Also set importance + event_date + content_hash so the trailing columns
        // carry non-NULL values (content_hash is the last projected column, idx 33).
        {
            let conn = db.conn.lock().await;
            conn.execute(
                "UPDATE memories SET importance = 9, event_date = 1779602400, content_hash = 'cafebabe_corrupt_net' WHERE source_id = 'corrupt_net'",
                libsql::params![],
            )
            .await
            .unwrap();
        }

        let results = db
            .search_memory(
                "Postgres MVCC concurrency control transactional",
                10,
                None,
                None,
                None,
                None,
                None,
                None,
            )
            .await
            .unwrap();
        let r = results
            .iter()
            .find(|r| r.source_id == "corrupt_net")
            .expect("corrupt_net memory should be retrievable");

        // Every positional field must round-trip unchanged (index-drift net).
        assert_eq!(r.quality.as_deref(), Some("high"), "quality (idx 22)");
        assert_eq!(
            r.stability.as_deref(),
            Some("learned"),
            "stability (idx 19)"
        );
        assert_eq!(r.version, 1, "version (idx 28)");
        assert!(!r.pending_revision, "pending_revision (idx 29)");
        assert_eq!(
            r.source_text.as_deref(),
            Some("ORIGINAL SOURCE TEXT MARKER"),
            "source_text (idx 27)",
        );
        let conf = r.confidence.expect("confidence (idx 17) present");
        assert!((conf - 0.83).abs() < 1e-4, "confidence = {conf}");
        assert!(r.space.as_deref() == Some("databases"), "space (idx 15)");
        assert!(
            r.memory_type.as_deref() == Some("fact"),
            "memory_type (idx 14)"
        );
        // score (idx 30) is sane (non-zero, finite).
        assert!(
            r.score.is_finite() && r.score > 0.0,
            "score (idx 30) = {}",
            r.score
        );
        // importance (idx 31) round-trips — completes the corruption net.
        assert_eq!(r.importance, Some(9), "importance (idx 31)");
        // event_date (idx 32) round-trips.
        assert_eq!(
            r.event_date,
            Some(1_779_602_400),
            "event_date (idx 32) round-trips"
        );
        // content_hash (idx 33) round-trips — pins the trailing-column alignment
        // (the per-document retrieval cap keys on this exact column).
        assert_eq!(
            r.content_hash.as_deref(),
            Some("cafebabe_corrupt_net"),
            "content_hash (idx 33) round-trips"
        );
    }

    // Salience tests read/write the process-global `WENLAN_ENABLE_SALIENCE_PRIOR`.
    // `temp_env::async_with_vars` mutates that global, so two salience tests
    // running concurrently can corrupt each other's flag mid-`.await`. Serialize
    // them on a process-local async lock (same pattern as `PRF_ENV_LOCK` above).
    static SALIENCE_ENV_LOCK: tokio::sync::Mutex<()> = tokio::sync::Mutex::const_new(());

    #[tokio::test]
    async fn salience_reorders_when_flag_on() {
        let _serial = SALIENCE_ENV_LOCK.lock().await;
        let (db, _dir) = test_db().await;
        let doc_a = make_memory_doc(
            "sal_a",
            "Kubernetes orchestrates containers in production clusters for scalable workloads",
            "fact",
            "devops",
            "claude",
        );
        let doc_b = make_memory_doc(
            "sal_b",
            "Kubernetes orchestrates containers in staging clusters for development workloads",
            "fact",
            "devops",
            "claude",
        );
        db.upsert_documents(vec![doc_a, doc_b]).await.unwrap();
        {
            let conn = db.conn.lock().await;
            conn.execute(
                "UPDATE memories SET importance = 10 WHERE source_id = 'sal_a'",
                libsql::params![],
            )
            .await
            .unwrap();
            conn.execute(
                "UPDATE memories SET importance = 1 WHERE source_id = 'sal_b'",
                libsql::params![],
            )
            .await
            .unwrap();
        }
        let results =
            temp_env::async_with_vars([("WENLAN_ENABLE_SALIENCE_PRIOR", Some("1"))], async {
                db.search_memory(
                    "Kubernetes container orchestration",
                    10,
                    None,
                    None,
                    None,
                    None,
                    None,
                    None,
                )
                .await
                .unwrap()
            })
            .await;
        let a = results.iter().find(|r| r.source_id == "sal_a");
        let b = results.iter().find(|r| r.source_id == "sal_b");
        if let (Some(a), Some(b)) = (a, b) {
            assert!(
                a.score > b.score,
                "importance=10 ({}) should outrank importance=1 ({})",
                a.score,
                b.score,
            );
        } else {
            panic!("both sal_a and sal_b should be retrievable");
        }
    }

    #[tokio::test]
    async fn salience_inert_when_flag_off() {
        let _serial = SALIENCE_ENV_LOCK.lock().await;
        let (db, _dir) = test_db().await;
        let doc_a = make_memory_doc(
            "inert_a",
            "Kubernetes orchestrates containers in production clusters for scalable workloads",
            "fact",
            "devops",
            "claude",
        );
        let doc_b = make_memory_doc(
            "inert_b",
            "Kubernetes orchestrates containers in staging clusters for development workloads",
            "fact",
            "devops",
            "claude",
        );
        db.upsert_documents(vec![doc_a, doc_b]).await.unwrap();
        {
            let conn = db.conn.lock().await;
            conn.execute(
                "UPDATE memories SET importance = 10 WHERE source_id = 'inert_a'",
                libsql::params![],
            )
            .await
            .unwrap();
            conn.execute(
                "UPDATE memories SET importance = 1 WHERE source_id = 'inert_b'",
                libsql::params![],
            )
            .await
            .unwrap();
        }
        // Baseline: flag explicitly unset.
        let baseline =
            temp_env::async_with_vars([("WENLAN_ENABLE_SALIENCE_PRIOR", None::<&str>)], async {
                db.search_memory(
                    "Kubernetes container orchestration",
                    10,
                    None,
                    None,
                    None,
                    None,
                    None,
                    None,
                )
                .await
                .unwrap()
            })
            .await;
        let base_a = baseline
            .iter()
            .find(|r| r.source_id == "inert_a")
            .map(|r| r.score);
        let base_b = baseline
            .iter()
            .find(|r| r.source_id == "inert_b")
            .map(|r| r.score);
        // With the flag OFF, importance must not influence scores: re-running with
        // flag OFF a second time is identical, and the high-importance row is NOT
        // boosted above what the base formula produces.
        let again =
            temp_env::async_with_vars([("WENLAN_ENABLE_SALIENCE_PRIOR", Some("0"))], async {
                db.search_memory(
                    "Kubernetes container orchestration",
                    10,
                    None,
                    None,
                    None,
                    None,
                    None,
                    None,
                )
                .await
                .unwrap()
            })
            .await;
        let again_a = again
            .iter()
            .find(|r| r.source_id == "inert_a")
            .map(|r| r.score);
        let again_b = again
            .iter()
            .find(|r| r.source_id == "inert_b")
            .map(|r| r.score);
        let base_a = base_a.expect("inert_a should be retrievable");
        let again_a = again_a.expect("inert_a should be retrievable on rerun");
        let base_b = base_b.expect("inert_b should be retrievable");
        let again_b = again_b.expect("inert_b should be retrievable on rerun");
        assert!(
            (base_a - again_a).abs() < 1e-6,
            "flag OFF must be stable within score epsilon (a): {base_a} vs {again_a}"
        );
        assert!(
            (base_b - again_b).abs() < 1e-6,
            "flag OFF must be stable within score epsilon (b): {base_b} vs {again_b}"
        );
    }

    /// L4 cold-start neutrality: all importance NULL + flag ON must produce the
    /// SAME ranking as flag OFF (salience_mult forced to 1.0 by None short-circuit).
    #[tokio::test]
    async fn salience_null_rows_unchanged() {
        let _serial = SALIENCE_ENV_LOCK.lock().await;
        let (db, _dir) = test_db().await;
        let doc_a = make_memory_doc(
            "null_a",
            "Kubernetes orchestrates containers in production clusters for scalable workloads",
            "fact",
            "devops",
            "claude",
        );
        let doc_b = make_memory_doc(
            "null_b",
            "Kubernetes orchestrates containers in staging clusters for development workloads",
            "fact",
            "devops",
            "claude",
        );
        db.upsert_documents(vec![doc_a, doc_b]).await.unwrap();
        // No importance set -> all NULL.
        let off =
            temp_env::async_with_vars([("WENLAN_ENABLE_SALIENCE_PRIOR", None::<&str>)], async {
                db.search_memory(
                    "Kubernetes container orchestration",
                    10,
                    None,
                    None,
                    None,
                    None,
                    None,
                    None,
                )
                .await
                .unwrap()
            })
            .await;
        let on = temp_env::async_with_vars([("WENLAN_ENABLE_SALIENCE_PRIOR", Some("1"))], async {
            db.search_memory(
                "Kubernetes container orchestration",
                10,
                None,
                None,
                None,
                None,
                None,
                None,
            )
            .await
            .unwrap()
        })
        .await;
        assert_eq!(off.len(), on.len(), "result count identical");
        for (o, n) in off.iter().zip(on.iter()) {
            assert_eq!(
                o.source_id, n.source_id,
                "ordering identical (NULL cold-start)"
            );
            assert!(
                (o.score - n.score).abs() < 1e-6,
                "score identical for {}: off={} on={}",
                o.source_id,
                o.score,
                n.score,
            );
        }
    }

