    // ==================== Knowledge Graph: full lifecycle ====================

    #[tokio::test]
    async fn test_knowledge_graph_full_lifecycle() {
        let (db, _dir) = test_db().await;

        // Create entities
        let rust = db
            .store_entity("Rust", "language", Some("tech"), Some("claude"), Some(0.99))
            .await
            .unwrap();
        let origin = db
            .store_entity(
                "Wenlan",
                "project",
                Some("tech"),
                Some("claude"),
                Some(0.95),
            )
            .await
            .unwrap();

        // Add observations
        let obs = db
            .add_observation(
                &rust,
                "Rust is a systems language",
                Some("claude"),
                Some(0.9),
            )
            .await
            .unwrap();
        assert!(!obs.is_empty());

        let obs2 = db
            .add_observation(
                &origin,
                "Wenlan uses Rust for backend",
                Some("claude"),
                None,
            )
            .await
            .unwrap();
        assert!(!obs2.is_empty());

        // Create relation
        let rel = db
            .create_relation(&origin, &rust, "uses", Some("claude"), None, None, None)
            .await
            .unwrap();
        assert!(!rel.is_empty());

        // Verify entities can be queried (via raw SQL to confirm data is in DB)
        let conn = db.conn.lock().await;
        let mut rows = conn
            .query("SELECT COUNT(*) FROM entities", ())
            .await
            .unwrap();
        if let Ok(Some(row)) = rows.next().await {
            let count: i64 = row.get(0).unwrap();
            assert_eq!(count, 2);
        }

        let mut rows = conn
            .query("SELECT COUNT(*) FROM observations", ())
            .await
            .unwrap();
        if let Ok(Some(row)) = rows.next().await {
            let count: i64 = row.get(0).unwrap();
            assert_eq!(count, 2);
        }

        let mut rows = conn
            .query("SELECT COUNT(*) FROM relations", ())
            .await
            .unwrap();
        if let Ok(Some(row)) = rows.next().await {
            let count: i64 = row.get(0).unwrap();
            assert_eq!(count, 1);
        }
    }

