    // ==================== T21 Eviction (archive-not-delete) ====================

    /// Helper: insert a memory then force its effective_confidence + last_accessed
    /// (and optionally confirmed/pinned) to specific values for eviction tests.
    /// `last_accessed_sql` is a SQL expression evaluated at UPDATE time, e.g.
    /// "strftime('%s','now','-120 days')" (aged) or "datetime('now')" (fresh).
    #[allow(clippy::too_many_arguments)]
    async fn seed_evict_row(
        db: &MemoryDB,
        source_id: &str,
        memory_type: &str,
        space: &str,
        eff_conf: f64,
        last_accessed_sql: &str,
        confirmed: bool,
        pinned: bool,
    ) {
        let doc = make_memory_doc(
            source_id,
            "evict test body content",
            memory_type,
            space,
            "claude",
        );
        db.upsert_documents(vec![doc]).await.unwrap();
        let conn = db.conn.lock().await;
        conn.execute(
            &format!(
                "UPDATE memories SET effective_confidence = ?1, last_accessed = {} \
                 WHERE source_id = ?2 AND source = 'memory'",
                last_accessed_sql
            ),
            libsql::params![eff_conf, source_id],
        )
        .await
        .unwrap();
        if pinned {
            conn.execute(
                "UPDATE memories SET pinned = 1 WHERE source_id = ?1 AND source = 'memory'",
                libsql::params![source_id],
            )
            .await
            .unwrap();
        }
        if confirmed {
            conn.execute(
                "UPDATE memories SET confirmed = 1 WHERE source_id = ?1 AND source = 'memory'",
                libsql::params![source_id],
            )
            .await
            .unwrap();
        }
    }

    async fn count_archived(db: &MemoryDB) -> i64 {
        let conn = db.conn.lock().await;
        let mut rows = conn
            .query(
                "SELECT COUNT(*) FROM memories WHERE source = 'memory' AND supersede_mode = 'evicted'",
                (),
            )
            .await
            .unwrap();
        let row = rows.next().await.unwrap().unwrap();
        row.get::<i64>(0).unwrap()
    }

    async fn count_rows(db: &MemoryDB) -> i64 {
        let conn = db.conn.lock().await;
        let mut rows = conn
            .query("SELECT COUNT(*) FROM memories WHERE source = 'memory'", ())
            .await
            .unwrap();
        let row = rows.next().await.unwrap().unwrap();
        row.get::<i64>(0).unwrap()
    }

    // `WENLAN_ENABLE_EVICTION` is a process-global env var read synchronously
    // by `eviction_enabled()` inside the refinery's Evict phase gate AND by
    // every eviction test below via `evict_stale`. `temp_env::async_with_vars`
    // mutates that global for the duration of a future but does not
    // serialize against other tests doing the same (or against tests that
    // merely read the ambient value across an `.await`) — two such tests
    // running concurrently can corrupt each other's view of the flag mid-run.
    // This is the ONE crate-shared lock (`pub(crate)` so
    // `crate::refinery::tests` can import and share it too — see that
    // module's Daily/Backstop trigger tests, which read this same ambient
    // flag) that every reader AND mutator of `WENLAN_ENABLE_EVICTION` must
    // take, mirroring the `PRF_ENV_LOCK` / `SALIENCE_ENV_LOCK` /
    // `RERANK_BLEND_ENV_LOCK` / `MAGNITUDE_ENV_LOCK` precedent above (a
    // `tokio::sync::Mutex` avoids the `await_holding_lock` lint a
    // `std::sync::Mutex` would trip).
    pub(crate) static EVICT_ENV_LOCK: tokio::sync::Mutex<()> = tokio::sync::Mutex::const_new(());

    // A1 — stale low-confidence aged rows get archived, never deleted.
    #[tokio::test]
    async fn test_evict_stale_archives_low_confidence_aged_rows() {
        let _serial = EVICT_ENV_LOCK.lock().await;
        let (db, _dir) = test_db().await;
        for i in 0..3 {
            seed_evict_row(
                &db,
                &format!("stale_{i}"),
                "fact",
                "engineering",
                0.05,
                "strftime('%s','now','-120 days')",
                false,
                false,
            )
            .await;
        }
        let before = count_rows(&db).await;
        let report = temp_env::async_with_vars([("WENLAN_ENABLE_EVICTION", Some("1"))], async {
            db.evict_stale(&crate::tuning::EvictionConfig::default())
                .await
                .unwrap()
        })
        .await;
        assert_eq!(report.archived, 3, "all 3 stale rows archived");
        assert_eq!(report.deleted, 0, "Stage 1 never deletes");
        assert!(!report.skipped_disabled);
        assert_eq!(
            count_archived(&db).await,
            3,
            "3 rows now supersede_mode=archive"
        );
        assert_eq!(
            count_rows(&db).await,
            before,
            "row count unchanged — archive, not delete"
        );
    }

