    #[tokio::test]
    async fn test_migration_24_renames_chunks_to_memories() {
        // This test verifies the migration works by checking that
        // after MemoryDB::new() on a fresh DB, the memories table exists
        // and chunks does not.
        let dir = tempfile::tempdir().unwrap();
        let db = MemoryDB::new(dir.path(), Arc::new(crate::events::NoopEmitter))
            .await
            .unwrap();

        let conn = db.conn.lock().await;

        // memories table should exist
        let mut rows = conn
            .query(
                "SELECT name FROM sqlite_master WHERE type='table' AND name='memories'",
                (),
            )
            .await
            .unwrap();
        assert!(
            rows.next().await.unwrap().is_some(),
            "memories table should exist"
        );
        drop(rows);

        // chunks table should NOT exist
        let mut rows = conn
            .query(
                "SELECT name FROM sqlite_master WHERE type='table' AND name='chunks'",
                (),
            )
            .await
            .unwrap();
        assert!(
            rows.next().await.unwrap().is_none(),
            "chunks table should not exist"
        );
        drop(rows);

        // user_version should be >= 24
        let mut rows = conn.query("PRAGMA user_version", ()).await.unwrap();
        let version: i64 = rows.next().await.unwrap().unwrap().get(0).unwrap();
        assert!(
            version >= 24,
            "user_version should be >= 24, got {}",
            version
        );
    }

    #[tokio::test]
    async fn test_sub_cluster_by_tokens() {
        let memories: Vec<ClusterMemRow> = (0..6)
            .map(|i| {
                let mut emb = vec![0.0f32; 768];
                if i < 3 {
                    emb[0] = 1.0 + (i as f32 * 0.05);
                    emb[1] = 0.1 * i as f32;
                } else {
                    emb[0] = 0.1 * (i - 3) as f32;
                    emb[1] = 1.0 + ((i - 3) as f32 * 0.05);
                }
                ClusterMemRow {
                    source_id: format!("mem_{}", i),
                    content: "x".repeat(3985),
                    entity_id: Some("entity_test".to_string()),
                    entity_name: Some("Test Entity".to_string()),
                    can_seed_page: true,
                    space: Some("test".to_string()),
                    embedding: emb,
                }
            })
            .collect();

        let indices: Vec<usize> = (0..6).collect();
        let cluster = build_distillation_cluster(&memories, &indices);
        assert!(cluster.estimated_tokens > 3500);

        let result = sub_cluster_by_tokens(&memories, cluster, 3500, 2);
        assert!(result.len() >= 2);
        for sub in &result {
            assert!(
                sub.estimated_tokens <= 3500,
                "sub-cluster too large: {}",
                sub.estimated_tokens
            );
            assert!(!sub.source_ids.is_empty());
        }
        let mut all_ids: Vec<String> = result.iter().flat_map(|c| c.source_ids.clone()).collect();
        all_ids.sort();
        let mut expected: Vec<String> = (0..6).map(|i| format!("mem_{}", i)).collect();
        expected.sort();
        assert_eq!(all_ids, expected);
    }

    #[test]
    fn sub_cluster_by_tokens_drops_single_member_subclusters_after_split() {
        // A token-split can strand a single memory in its own sub-cluster
        // (the farthest-first orthogonal outlier). The floor re-check (spec
        // §4.3) must drop such singletons. Setup: 3 near-identical memories +
        // 1 orthogonal one, over a token limit that forces a k=2 split ->
        // groups [0,1,2] and [3]; the singleton [3] must be dropped.
        let memories: Vec<ClusterMemRow> = (0..4)
            .map(|i| {
                let mut emb = vec![0.0f32; 768];
                if i < 3 {
                    emb[0] = 1.0;
                    emb[1] = 0.01 * i as f32;
                } else {
                    emb[0] = 0.0;
                    emb[1] = 1.0;
                }
                ClusterMemRow {
                    source_id: format!("mem_{}", i),
                    content: "x".repeat(340),
                    entity_id: Some("entity_test".to_string()),
                    entity_name: Some("Test Entity".to_string()),
                    can_seed_page: true,
                    space: Some("test".to_string()),
                    embedding: emb,
                }
            })
            .collect();

        let indices: Vec<usize> = (0..4).collect();
        let cluster = build_distillation_cluster(&memories, &indices);
        assert!(cluster.estimated_tokens > 450);

        let result = sub_cluster_by_tokens(&memories, cluster, 450, 2);

        assert!(
            result.iter().all(|cluster| cluster.source_ids.len() > 1),
            "token split must re-check the member floor and drop singleton subclusters: {:?}",
            result
                .iter()
                .map(|cluster| cluster.source_ids.clone())
                .collect::<Vec<_>>()
        );
    }

    #[tokio::test]
    async fn test_source_sync_state_crud() {
        let (db, _dir) = test_db().await;

        // Upsert
        db.upsert_sync_state("obsidian-main", "/vault/note.md", 1712678400_i64, "abc123")
            .await
            .unwrap();

        // Get
        let state = db
            .get_sync_state("obsidian-main", "/vault/note.md")
            .await
            .unwrap();
        assert!(state.is_some());
        let s = state.unwrap();
        assert_eq!(s.content_hash, "abc123");
        assert_eq!(s.mtime_ns, 1712678400);

        // Update
        db.upsert_sync_state("obsidian-main", "/vault/note.md", 1712678500_i64, "def456")
            .await
            .unwrap();
        let updated = db
            .get_sync_state("obsidian-main", "/vault/note.md")
            .await
            .unwrap()
            .unwrap();
        assert_eq!(updated.content_hash, "def456");

        // List all for source
        db.upsert_sync_state("obsidian-main", "/vault/other.md", 1712678600_i64, "ghi789")
            .await
            .unwrap();
        let all = db.list_sync_state_paths("obsidian-main").await.unwrap();
        assert_eq!(all.len(), 2);

        // Delete one
        db.delete_sync_state("obsidian-main", "/vault/note.md")
            .await
            .unwrap();
        let gone = db
            .get_sync_state("obsidian-main", "/vault/note.md")
            .await
            .unwrap();
        assert!(gone.is_none());

        // Delete all for source
        db.delete_all_sync_state("obsidian-main").await.unwrap();
        let empty = db.list_sync_state_paths("obsidian-main").await.unwrap();
        assert!(empty.is_empty());
    }

    #[tokio::test]
    async fn test_document_enrichment_queue_state() {
        let (db, _dir) = test_db().await;

        // ── enqueue two docs; claim returns them one at a time ──────────────
        db.enqueue_document("folder-notes", "/notes/a.md", Some("hashA"))
            .await
            .unwrap();
        db.enqueue_document("folder-notes", "/notes/b.md", Some("hashB"))
            .await
            .unwrap();

        let first = db.claim_next_pending().await.unwrap().expect("first claim");
        let second = db
            .claim_next_pending()
            .await
            .unwrap()
            .expect("second claim");
        // Oldest-enqueued first (serial claim).
        assert_eq!(first.file_path, "/notes/a.md");
        assert_eq!(second.file_path, "/notes/b.md");
        // A freshly claimed doc has no completed chunk yet and is in_progress.
        assert_eq!(first.last_completed_chunk, -1);
        assert_eq!(first.status, "in_progress");
        // Both are now in_progress → nothing else claimable.
        assert!(db.claim_next_pending().await.unwrap().is_none());

        // ── checkpoint then resume from the saved chunk ─────────────────────
        db.checkpoint_chunk("folder-notes", "/notes/a.md", 3)
            .await
            .unwrap();
        // Pause it (interrupted attempt, retry available now) so it is claimable.
        db.mark_paused(
            "folder-notes",
            "/notes/a.md",
            "interrupted",
            Some(chrono::Utc::now().timestamp()),
        )
        .await
        .unwrap();
        let resumed = db
            .claim_next_pending()
            .await
            .unwrap()
            .expect("resumed claim");
        assert_eq!(resumed.file_path, "/notes/a.md");
        assert_eq!(
            resumed.last_completed_chunk, 3,
            "claim resumes from the checkpointed chunk"
        );
        assert_eq!(resumed.attempt_count, 1, "pause bumped the retry attempt");
        assert_eq!(resumed.error_detail.as_deref(), Some("interrupted"));

        // ── enqueue same doc twice inserts one row (idempotent no-op) ───────
        // Re-enqueue the in-progress doc; it must NOT reset the checkpoint.
        db.enqueue_document("folder-notes", "/notes/a.md", Some("hashA"))
            .await
            .unwrap();
        let after_reenqueue = db
            .get_queue_entry("folder-notes", "/notes/a.md")
            .await
            .unwrap()
            .unwrap();
        assert_eq!(
            after_reenqueue.status, "in_progress",
            "re-enqueue of an existing doc is a no-op"
        );
        assert_eq!(
            after_reenqueue.last_completed_chunk, 3,
            "re-enqueue preserves the checkpoint"
        );
        let row_count: i64 = {
            let conn = db.conn.lock().await;
            let mut rows = conn
                .query(
                    "SELECT COUNT(*) FROM document_enrichment_queue
                     WHERE source_id = ?1 AND file_path = ?2",
                    libsql::params!["folder-notes", "/notes/a.md"],
                )
                .await
                .unwrap();
            rows.next().await.unwrap().unwrap().get::<i64>(0).unwrap()
        };
        assert_eq!(row_count, 1, "enqueue twice inserts one row");

        // ── mark_done removes it from the claimable set ─────────────────────
        db.mark_done("folder-notes", "/notes/a.md").await.unwrap();
        let done = db
            .get_queue_entry("folder-notes", "/notes/a.md")
            .await
            .unwrap()
            .unwrap();
        assert_eq!(done.status, "done");
        // a.md done, b.md still in_progress → nothing claimable.
        assert!(db.claim_next_pending().await.unwrap().is_none());

        // ── dequeue_by_source cancels only that source's rows ───────────────
        db.enqueue_document("folder-other", "/other/c.md", None)
            .await
            .unwrap();
        db.dequeue_by_source("folder-notes").await.unwrap();
        assert!(
            db.get_queue_entry("folder-notes", "/notes/a.md")
                .await
                .unwrap()
                .is_none(),
            "dequeue_by_source removed the done row"
        );
        assert!(
            db.get_queue_entry("folder-notes", "/notes/b.md")
                .await
                .unwrap()
                .is_none(),
            "dequeue_by_source removed the in_progress row"
        );
        // The other source's row survives and is still claimable.
        let survivor = db
            .claim_next_pending()
            .await
            .unwrap()
            .expect("other source's row survives dequeue");
        assert_eq!(survivor.source_id, "folder-other");
        assert_eq!(survivor.file_path, "/other/c.md");
        assert_eq!(survivor.content_hash, None);
    }

    #[tokio::test]
    async fn migration_66_idempotent() {
        let (db, _dir) = test_db().await;
        // Roll user_version back to 65 and re-run migrations: the queue table's
        // CREATE ... IF NOT EXISTS must replay without error.
        {
            let conn = db.conn.lock().await;
            conn.execute("PRAGMA user_version = 65", ()).await.unwrap();
        }
        db.run_migrations(&crate::events::NoopEmitter)
            .await
            .expect("re-run migrations idempotent");
        let conn = db.conn.lock().await;
        // Table still present.
        let mut trows = conn
            .query(
                "SELECT COUNT(*) FROM sqlite_master WHERE type='table' AND name='document_enrichment_queue'",
                (),
            )
            .await
            .unwrap();
        let present: i64 = trows.next().await.unwrap().unwrap().get(0).unwrap();
        assert_eq!(present, 1, "document_enrichment_queue table must exist");
        // user_version restored to current SCHEMA_VERSION.
        let mut vrows = conn.query("PRAGMA user_version", ()).await.unwrap();
        let uv: i64 = vrows.next().await.unwrap().unwrap().get(0).unwrap();
        assert_eq!(uv as u32, crate::db::SCHEMA_VERSION);
    }

