    /// Summary rows must NOT enter the reranker candidate list.
    #[tokio::test]
    async fn test_global_prelude_summary_rows_excluded_from_rerank() {
        use crate::reranker::Reranker;
        use std::sync::{Arc, Mutex};

        struct RecordingReranker {
            seen: Arc<Mutex<Vec<String>>>,
        }
        impl Reranker for RecordingReranker {
            fn rerank(
                &self,
                _q: &str,
                candidates: &[(String, String)],
            ) -> Result<Vec<(String, f32)>, WenlanError> {
                let mut s = self.seen.lock().unwrap();
                for (id, _) in candidates {
                    s.push(id.clone());
                }
                // Keep original order (return empty so caller keeps order).
                Ok(Vec::new())
            }
            fn model_id(&self) -> &str {
                "recording-test"
            }
        }

        let (db, _tmp) = test_db().await;
        db.upsert_documents(vec![make_memory_doc(
            "m_a",
            "rust systems programming memory safety",
            "fact",
            "work",
            "claude-code",
        )])
        .await
        .unwrap();
        seed_summary_node(
            &db,
            "sum_root",
            1,
            None,
            "Overview",
            "rust corpus overview body",
            &["m_a"],
        )
        .await;
        seed_summary_node(
            &db,
            "sum_b_1",
            0,
            Some("1"),
            "Rust",
            "rust systems programming memory safety",
            &["m_a"],
        )
        .await;

        let seen = Arc::new(Mutex::new(Vec::new()));
        let reranker: Arc<dyn Reranker> = Arc::new(RecordingReranker { seen: seen.clone() });
        let _ = temp_env::async_with_vars([("WENLAN_ENABLE_GLOBAL_PRELUDE", Some("1"))], async {
            db.search_memory_cross_rerank("rust programming", 10, None, None, None, Some(reranker))
                .await
                .unwrap()
        })
        .await;
        let candidate_ids = seen.lock().unwrap();
        assert!(
            candidate_ids.iter().all(|id| !id.starts_with("sum_")),
            "no summary node may enter the rerank candidate list, saw {:?}",
            *candidate_ids
        );
    }

    /// WENLAN_RERANK_SKIP_PREFERENCE: preference-intent queries bypass the CE
    /// reranker entirely (base-path ranking, CE never invoked); non-preference
    /// queries still rerank; flag unset (default) = CE always runs.
    #[tokio::test]
    async fn test_rerank_skip_preference_bypasses_ce() {
        use crate::reranker::Reranker;
        use std::sync::{Arc, Mutex};

        struct CountingReranker {
            calls: Arc<Mutex<usize>>,
        }
        impl Reranker for CountingReranker {
            fn rerank(
                &self,
                _q: &str,
                _candidates: &[(String, String)],
            ) -> Result<Vec<(String, f32)>, WenlanError> {
                *self.calls.lock().unwrap() += 1;
                Ok(Vec::new()) // keep original order
            }
            fn model_id(&self) -> &str {
                "counting-test"
            }
        }

        let (db, _tmp) = test_db().await;
        db.upsert_documents(vec![
            make_memory_doc(
                "m_rust",
                "rust systems programming memory safety",
                "fact",
                "work",
                "claude-code",
            ),
            make_memory_doc(
                "m_video",
                "video editing resources and tutorials",
                "fact",
                "work",
                "claude-code",
            ),
        ])
        .await
        .unwrap();

        let pref_query = "Can you recommend some resources for learning video editing?";

        // Flag ON + preference query: CE never invoked, results == base path.
        let calls = Arc::new(Mutex::new(0usize));
        let reranker: Arc<dyn Reranker> = Arc::new(CountingReranker {
            calls: calls.clone(),
        });
        let (bypassed, base) =
            temp_env::async_with_vars([("WENLAN_RERANK_SKIP_PREFERENCE", Some("1"))], async {
                let bypassed = db
                    .search_memory_cross_rerank(
                        pref_query,
                        10,
                        None,
                        None,
                        None,
                        Some(reranker.clone()),
                    )
                    .await
                    .unwrap();
                let base = db
                    .search_memory(pref_query, 10, None, None, None, None, None, None)
                    .await
                    .unwrap();
                (bypassed, base)
            })
            .await;
        assert_eq!(
            *calls.lock().unwrap(),
            0,
            "CE must not be invoked for a preference-intent query when the skip flag is on"
        );
        let bypassed_ids: Vec<&str> = bypassed.iter().map(|r| r.id.as_str()).collect();
        let base_ids: Vec<&str> = base.iter().map(|r| r.id.as_str()).collect();
        assert_eq!(
            bypassed_ids, base_ids,
            "bypassed preference query must return the base-path ranking"
        );

        // Flag ON + non-preference query: CE still runs.
        let _ = temp_env::async_with_vars(
            [("WENLAN_RERANK_SKIP_PREFERENCE", Some("1"))],
            db.search_memory_cross_rerank(
                "rust programming",
                10,
                None,
                None,
                None,
                Some(reranker.clone()),
            ),
        )
        .await
        .unwrap();
        assert!(
            *calls.lock().unwrap() > 0,
            "CE must still run for non-preference queries with the skip flag on"
        );

        // Flag unset (default) + preference query: CE still runs.
        let before = *calls.lock().unwrap();
        let _ = temp_env::async_with_vars(
            [("WENLAN_RERANK_SKIP_PREFERENCE", None::<&str>)],
            db.search_memory_cross_rerank(pref_query, 10, None, None, None, Some(reranker.clone())),
        )
        .await
        .unwrap();
        assert!(
            *calls.lock().unwrap() > before,
            "default (flag unset) must keep the CE on even for preference queries"
        );
    }

